import { createRouter, createWebHashHistory } from "vue-router";
import TrendsCharts from "@/views/TrendsCharts/TrendsCharts.vue";
import TabWizard from "@/views/TabsWizard/TabWizard.vue";

const router =  createRouter({
  history: createWebHashHistory("/"),
  routes: [
    {
      path: "/",
      name: "home",
      component: TabWizard,
    },
    {
      path: "/TrendsCharts",
      name: "TrendsCharts",
      component: TrendsCharts,
    },
  ],
});

export default router;