<template>
  <div class="wcag-desktop-tab">
    <div class="wcag-heading">
      <h2>{{ props.tabObject.header }}</h2>
    </div>

    <div class="wcag-alerts">
      <v-alert
        v-if="selectedImpacts.length === 0"
        dense
        outlined
        prominent
        type="warning"
      >
        <span>
          No Impact is selected. Please select atleast one impact to see data.
        </span>
      </v-alert>
      <v-alert
        v-if="selectedImpacts.length > 0 && displayWarningMessage"
        dense
        outlined
        prominent
        type="warning"
      >
        <span
          >There are no records for the selected impact
          <b>{{ selectedImpacts.join(",") }}</b
          >.</span
        >
      </v-alert>
    </div>

    <v-divider></v-divider>

    <div class="summary-container">
      <v-card class="wcag-summary" width="50%">
        <v-card-title>Summary</v-card-title>
        <v-card-text>
          <v-table>
            <template v-slot:default>
              <tbody>
                <tr v-for="item in summaryData" :key="item.name">
                  <td class="subtitle1">{{ item.name }}</td>

                  <td v-if="item.name === 'WCAG Conformance Level'">
                    <b>{{ item.value }}</b>
                  </td>
                  <td v-else>{{ item.value }}</td>
                </tr>
              </tbody>
            </template>
          </v-table>
        </v-card-text>
      </v-card>

      <v-card class="pie-chart" width="50%">
        <div class="chart-container">
          <highcharts :options="chartOptions" />
        </div>
      </v-card>
    </div>

    <v-divider></v-divider>

    <v-row class="wcag-filter-by-impact" data-html2canvas-ignore="true">
      <v-col cols="5">
        <v-select
          :items="impact"
          v-model="selectedImpacts"
          label="Filter by Impact"
          multiple
          variant="outlined"
          density="compact"
          item-title="title"
          item-value="value"
          :menu-props="{ scrollStrategy: 'none' }"
          placeholder="Filter by Imact"
          :eager="true"
          class="accessbilitySelector"
        >
          <template v-slot:prepend-item>
            <v-list-item
              title="Select All"
              @click="toggleInAccessbility"
              ripple
              @mousedown.prevent
            >
              <template v-slot:prepend>
                <v-checkbox-btn
                  color="selectedAllImpacts ? 'indigo-darken-4' : undefined"
                  :indeterminate="selectedSomeImpacts && !selectedAllImpacts"
                  :model-value="selectedAllImpacts"
                ></v-checkbox-btn>
              </template>
            </v-list-item>
            <v-divider class="mt-2"></v-divider>
          </template>
        </v-select>
      </v-col>
    </v-row>

    <v-table class="wcag-table">
      <thead>
        <tr>
          <th v-for="head in headers" :key="head.title" :width="head.width">
            {{ head.title }}
          </th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="item in scriptItems" :key="item.id">
          <td
            v-for="headerItem in headers"
            :key="item.id + headerItem.title"
            class="body1"
          >
            <div v-if="headerItem.key === 'action'" class="action-col">
              <div v-if="isNaN(item.action)">
                <div class="action-with-info">
                  <div
                    @click="showErrors(item.image, item.errors, item)"
                    class="info-icon"
                  >
                    <v-icon icon="mdi mdi-information"></v-icon>
                  </div>

                  <div>
                    {{ item.action }}
                  </div>
                </div>
              </div>
              <div v-else>
                {{ item.action }}
              </div>
            </div>
            <div
              v-else-if="
                [
                  'wcag2a',
                  'wcag2aa',
                  'wcag2aaa',
                  'miscellaneous',
                  'totalIssues',
                ].includes(headerItem.key)
              "
            >
              <div
                v-if="isNaN(item.action) && item[headerItem.key] > 0"
                @click="
                  showErrors(item.image, item.errors, item, headerItem.key)
                "
                class="clickable-link"
              >
                {{ item[headerItem.key] }}
              </div>
              <div v-else>{{ item[headerItem.key] }}</div>
            </div>
            <div v-else>
              {{ item[headerItem.key] }}
            </div>
          </td>
        </tr>
      </tbody>
    </v-table>

    <!-- error dialog -->
    <v-dialog
      v-model="errorDialog"
      class="error-dailog"
      :hide-overlay="hideOverlay"
      fullscreen
      persistent
      max-width="75%"
      aria-label="acc erros"
    >
      <v-card>
        <v-card-item>
          <v-card-title>
            <div class="error-dailog-title">
              <div>Errors - {{ actionName }}</div>
              <div class="error-action-btns">
                <div>
                  <v-btn color="success" @click="openAllCloseAllToggle()">{{
                    isAllExpanded ? "Collapse All" : "Expand All"
                  }}</v-btn>
                </div>
                <div
                  @click="errorDialog = false"
                  class="error-dailog-close-icon"
                >
                  <v-icon icon="mdi mdi-close"></v-icon>
                </div>
              </div>
            </div>
          </v-card-title>
        </v-card-item>
        <v-card-text class="error-dailog-text">
          <v-expansion-panels
            multiple
            focusable
            v-if="errors.length > 0"
            v-model="errorsExpansionPanel"
          >
            <v-expansion-panel v-for="(error, i) in errors" :key="i">
              <v-expansion-panel-title
                :color="i % 2 ? '#233e70' : '#3a6ac4'"
                style="font-size: 20px"
              >
                {{ error.category }}
              </v-expansion-panel-title>
              <v-expansion-panel-text>
                <div
                  v-html="setLinks(error.description)"
                  style="font-size: 18px"
                ></div>

                <div class="tags-container">
                  <span>Tags:</span>
                  <v-chip v-for="(tag, i) in error.tags" :key="i">
                    {{ tag }}
                  </v-chip>
                  <span
                    v-if="props.tabObject.type === 'accessibilityAndroid'"
                    class="helpIcon"
                    @click="showHelpInfo(error.errNodes)"
                  >
                    <v-icon icon="mdi-help"></v-icon>
                  </span>
                </div>
                <div>
                  <span style="font-weight: bold">Impact:</span>
                  <span
                    class="color_red"
                    v-if="
                      error.impact === 'critical' || error.impact === 'serious'
                    "
                  >
                    <a href="#">
                      <span class="tag tag-critical-serious tag-lg">
                        {{ error.impact }}
                      </span>
                    </a>
                  </span>
                  <span
                    class="color_yellow"
                    v-else-if="error.impact === 'moderate'"
                  >
                    <a href="#">
                      <span class="tag tag-moderate tag-lg">
                        {{ error.impact }}
                      </span>
                    </a>
                  </span>
                  <span
                    class="color_orange"
                    v-else-if="error.impact === 'minor'"
                  >
                    <a href="#">
                      <span class="tag tag-minor tag-lg">
                        {{ error.impact }}
                      </span>
                    </a>
                  </span>
                </div>
                <div v-for="(node, index) in error.errNodes" :key="index">
                  <!-- <v-row class="error-row"> -->
                  <v-row>
                    <v-col cols="2" v-if="baseImage !== ''">
                      <!-- <div>{{ node.rectangle.left }} , {{ dimension.width }}</div> -->
                      <div
                        v-if="node.rectangle.left < dimension.width"
                        class="element-screenshot"
                        @click="
                          expandImage(node.rectangle, error.highLightColor)
                        "
                      >
                        <!-- <v-card :ripple="false" class="portrait" :image="baseImage" height="150px"
                          width="200px" alt="screenshot"></v-card> -->
                        <!-- <img class="portrait" :src="baseImage" alt="acc screenshot"> -->
                        <div
                          class="portrait"
                          :style="{
                            'background-image': `url(${baseImage})`,
                          }"
                        ></div>
                      </div>
                    </v-col>
                    <v-col cols="9">
                      <div
                        class="tooltip"
                        v-if="
                          props.tabObject.type === 'accessibility' ||
                          props.tabObject.type === 'accessibilityMobile'
                        "
                      >
                        <div class="tooltip-ellipses">
                          <b>Label: </b>{{ node.label }}
                        </div>
                        <div class="tooltiptext">{{ node.label }}</div>
                      </div>
                      <div
                        class="tooltip"
                        v-if="
                          props.tabObject.type === 'accessibilityAndroid' &&
                          node.domPath
                        "
                      >
                        <div class="tooltip-ellipses">
                          <b>Dom Path: </b>{{ node.domPath }}
                        </div>
                        <div class="tooltiptext">{{ node.domPath }}</div>
                      </div>
                      <div class="tooltip">
                        <!-- <p style="font-size: 16px">{{ node.htmlSnippet }}</p> -->
                        <!-- <p style="font-size: 16px">
                          {{ node.htmlSnippet.length > 90 ? node.htmlSnippet.slice(0, 90) + "..." : node.htmlSnippet }}
                          <v-tooltip
                            activator="parent"
                            location="top"
                          >{{ node.htmlSnippet }}</v-tooltip>
                        </p> -->
                        <!-- <v-btn variant="text">
                          {{ node.htmlSnippet.length > 90 ? node.htmlSnippet.slice(0, 90) + "..." : node.htmlSnippet }}
                          <v-tooltip
                            activator="parent"
                            location="top"
                          >{{ node.htmlSnippet }}</v-tooltip>
                        </v-btn> -->

                        <div class="tooltip-ellipses">
                          <b>HTML Snippet: </b>{{ node.htmlSnippet }}
                        </div>
                        <div class="tooltiptext">{{ node.htmlSnippet }}</div>
                      </div>
                    </v-col>
                  </v-row>
                </div>
              </v-expansion-panel-text>
            </v-expansion-panel>
          </v-expansion-panels>
          <div v-else>
            <h2>
              You have selected below filters in Impact :
              {{ displaySepratedByComma(selectedImpacts) }}
            </h2>
          </div>
        </v-card-text>
      </v-card>
    </v-dialog>

    <!-- image dialog -->
    <v-dialog
      v-model="imageDialog"
      class="image-dailog"
      fullscreen
      :hide-overlay="hideOverlay"
      aria-label="acc erros image"
    >
      <v-card>
        <v-card-title>
          <div @click="errorDialog = false" class="error-dailog-close-icon">
            <!-- <v-icon icon="mdi mdi-close"></v-icon> -->
          </div>
        </v-card-title>
        <v-card-text>
          <div @click="imageDialog = false" class="text-center">
            <div class="element-screenshot__overlay">
              <div class="element-screenshot">
                <div class="element-screenshot__content">
                  <div
                    class="element-screenshot__image"
                    :style="{
                      'background-image': `url(${baseImage})`,
                      position: 'relative',
                      width: `${dimension.width}px`,
                      height: `${dimension.height}px`,
                      // 'background-size': `${imageWidth}px ${imageHeight}px`
                    }"
                  >
                    <div
                      class="element-screenshot__element-marker"
                      :style="{
                        position: 'absolute',
                        outline: `4px solid ${rectangleHighlightColor}`,
                        width: `${rectangle.width}px`,
                        height: `${rectangle.height}px`,
                        top: `${rectangle.top}px`,
                        left: `${rectangle.left}px`,
                      }"
                    ></div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </v-card-text>
      </v-card>
    </v-dialog>
    <!-- Help Dialog for an Andrioid mobile  -->
    <v-dialog v-model="helpDialog" class="helpDialog">
      <v-card>
        <v-card-title>
          <div
            @click="helpDialog = false"
            class="error-dailog-close-icon-help-info"
          >
            <v-icon icon="mdi mdi-close"></v-icon>
          </div>
        </v-card-title>
        <v-card-text>
          <div @click="helpDialog = false" class="text-center"></div>
          <div>
            <h1>What is this ?</h1>
            <div>{{ detail }}</div>
            <h1>
              Suggestion
              <v-icon icon="mdi mdi-lightbulb"></v-icon>
            </h1>
            <div>{{ suggestion }}</div>
          </div>
        </v-card-text>
      </v-card>
    </v-dialog>
  </div>
</template>

<script setup>
import { ref, reactive, onMounted, watch, computed, nextTick } from "vue";
import { uuid } from "vue-uuid";
import chartConfig from "../../config/chart.js";
import useWcagHelper from "../../use/useWcagHelper.js";
import useMetricsHelper from "../../use/useMetricsHelper.js";
import useCommonHelper from "../../use/useCommonHelper.js";

const props = defineProps(["tabObject"]);
const wcagHelper = useWcagHelper();
const metricsHelper = useMetricsHelper();
const commonHelper = useCommonHelper();

const accessibilityData = ref([]);
const scripts = ref([]);
const errors = ref([]);
const baseImage = ref("");
const dimension = ref({});
let rectangle = reactive({});
const errorDialog = ref(false);
const imageDialog = ref(false);
const helpDialog = ref(false);
const hideOverlay = ref(false);
const scriptItems = ref([]);
const summaryData = ref([]);
const summaryCategories = ref([]);
const headers = ref([]);
const selectedImpacts = ref(["wcag2a", "wcag2aa", "wcag2aaa", "miscellaneous"]);
const copyOfScript = ref([]);
const displayWarningMessage = ref(false);
let persona = reactive(null);
const imageHeight = ref("");
const imageWidth = ref("");
const rectangleHighlightColor = ref("");
const errorsExpansionPanel = ref([]);
const actionName = ref("");
const isAllExpanded = ref(false);
const detail = ref("");
const suggestion = ref("");
const chartOptions = ref({});

const impact = ref([
  { title: "WCAG-A", value: "wcag2a" },
  { title: "WCAG-AA", value: "wcag2aa" },
  { title: "WCAG-AAA", value: "wcag2aaa" },
  { title: "Miscellaneuos", value: "miscellaneous" },
]);

onMounted(() => {
  accessibilityData.value = props.tabObject.data.qumDataList;
  persona = props.tabObject.data.persona;
  initialiseUI();
});

watch(
  () => props.tabObject,
  (newVal) => {
    if (newVal.componentName === "AccessibilityTab") {
      accessibilityData.value = newVal.data.qumDataList;
      persona = newVal.data.persona;
      initialiseUI();
    }
  }
);

watch(errorDialog, (val) => {
  commonHelper.removeBodyScroll(val);
});

watch(errorsExpansionPanel, (val) => {
  if (val.length === 0) {
    isAllExpanded.value = false;
  } else {
    isAllExpanded.value = true;
  }
});

const selectedAllImpacts = computed(() => {
  filterBySelectedImpacts();
  return selectedImpacts.value.length === impact.value.length;
});
const selectedSomeImpacts = computed(() => {
  return selectedImpacts.value.length > 0;
});

const initialiseUI = () => {
  if (accessibilityData.value) {
    scriptItems.value = [];
    const scriptsData = accessibilityData.value;

    copyScriptDataAndAddAccssCategory(scriptsData);
    mapScriptData(scriptsData);

    createTableData();
    createSummary();
    addCategoryIssues(true);
  }
};

const copyScriptDataAndAddAccssCategory = (scriptsData) => {
  scriptsData.forEach((scr) => {
    scr.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.accessibilityData.forEach((step) => {
          step.errors.forEach((err) => {
            if (err.tags.includes("wcag2a")) {
              err["accessibilityCategory"] = "wcag2a";
            } else if (err.tags.includes("wcag2aa")) {
              err["accessibilityCategory"] = "wcag2aa";
            } else if (err.tags.includes("wcag2aaa")) {
              err["accessibilityCategory"] = "wcag2aaa";
            } else {
              err["accessibilityCategory"] = "miscellaneous";
            }
          });
        });
      });
    });
  });

  copyOfScript.value = JSON.parse(JSON.stringify(scriptsData));
};

const mapScriptData = (scriptsData) => {
  headers.value = [
    { title: "Tasks", key: "scenario", sortable: false, width: "10%" },
    { title: "Scenarios", key: "task", sortable: false, width: "15%" },
    { title: "Steps", key: "step", sortable: false, width: "10%" },
    { title: "Actions", key: "action", sortable: false, width: "20%" },
    { title: "WCAG-A", key: "wcag2a", sortable: false, width: "7%" },
    { title: "WCAG-AA", key: "wcag2aa", sortable: false, width: "7%" },
    { title: "WCAG-AAA", key: "wcag2aaa", sortable: false, width: "7%" },
    {
      title: "Miscellaneous",
      key: "miscellaneous",
      sortable: false,
      width: "12%",
    },
    {
      title: "Total Issues",
      key: "totalIssues",
      sortable: false,
      width: "10%",
    },
  ];
  scripts.value = scriptsData.map((scr) => {
    return {
      id: uuid.v4(),
      scriptName: scr.scriptName,
      onlyName: trimScriptName(scr.scriptName),
      highLightColor: scr.highLightColor,
      scenarios: scr.scenarios.map((scn) => {
        return {
          id: uuid.v4(),
          scenarioName: scn.scenarioName,
          activities: scn.activities.map((act) => {
            return {
              id: uuid.v4(),
              ...act,
              accessibilityData: act.accessibilityData.map((step) => {
                return {
                  id: uuid.v4(),
                  ...step,
                };
              }),
            };
          }),
        };
      }),
    };
  });
};

const createSummary = () => {
  let tasks = 0,
    steps = 0,
    actions = 0,
    // critical = 0,
    // serious = 0,
    // moderate = 0,
    // minor = 0,
    wcag2a = 0,
    wcag2aa = 0,
    wcag2aaa = 0,
    miscellaneous = 0,
    total = 0;

  scripts.value.forEach((script) => {
    const violations = wcagHelper.useSumOfCategoriesForScript(
      script,
      scriptItems.value
    );
    // critical += violations.critical;
    // serious += violations.serious;
    // moderate += violations.moderate;
    // minor += violations.minor;
    wcag2a += violations.wcag2a;
    wcag2aa += violations.wcag2aa;
    wcag2aaa += violations.wcag2aaa;
    miscellaneous += violations.miscellaneous;

    tasks += script.scenarios.length;
    script.scenarios.forEach((scenario) => {
      steps += scenario.activities.length;
      scenario.activities.forEach((activity) => {
        actions += activity.accessibilityData.length;
      });
    });
  });

  // total = critical + serious + moderate + minor;
  total = wcag2a + wcag2aa + wcag2aaa + miscellaneous;

  const conformanceLevel = wcagHelper.useConformanceLevel(
    wcag2a,
    wcag2aa,
    wcag2aaa
  );

  summaryData.value = [
    {
      name: "Name",
      value: window.info[0].applicationName,
    },
    {
      name: "Persona",
      value: persona,
    },
    {
      name: "Tasks",
      value: scripts.value.length,
    },
    {
      name: "Scenarios",
      value: tasks,
    },
    {
      name: "Steps",
      value: steps,
    },
    {
      name: "Actions",
      value: actions,
    },
    {
      name: "WCAG Conformance Level",
      value: conformanceLevel,
    },
  ];
  summaryCategories.value = [
    {
      name: "WCAG-A",
      y: wcag2a,
      color: "#ff433e",
      // color: "#007fff"
    },
    {
      name: "WCAG-AA",
      y: wcag2aa,
      color: "#ff9e34",
      // color: "#ffff00"
    },
    {
      name: "WCAG-AAA",
      y: wcag2aaa,
      color: "#ffff2e",
      // color: "#ff9900"
    },
    {
      name: "Miscellaneous",
      y: miscellaneous,
      color: "#3499ff",
      // color: "#ff0000"
    },
    // {
    //   name: "Total",
    //   violation: total,
    // },
  ];

  createPieChart();
};

const createPieChart = () => {
  chartOptions.value = {
    ...chartConfig,
    series: [
      {
        name: "Count",
        colorByPoint: true,
        data: summaryCategories.value,
      },
    ],
  };
};

const createTableData = () => {
  const scriptItemData = [];
  scripts.value.forEach((scr) => {
    const script = {
      id: scr.id,
      scenario: scr.onlyName,
      task: scr.scenarios.length,
      step: metricsHelper.useSumOfTasks(scr),
      action: metricsHelper.useSumOfActions(scr, "accessibility"),
    };
    scriptItemData.push(script);

    scr.scenarios.forEach((scn) => {
      const scenario = {
        id: scn.id,
        scenario: "",
        task: scn.scenarioName,
        step: scn.activities.length,
        action: metricsHelper.useSumOfActionsForScenario(scn, "accessibility"),
      };

      scriptItemData.push(scenario);

      scn.activities.forEach((act) => {
        const activity = {
          id: act.id,
          scenario: "",
          task: "",
          step: act.activityName,
          action: act.accessibilityData.length,
        };
        scriptItemData.push(activity);

        act.accessibilityData.forEach(async (step) => {
          let item = {
            id: step.id,
            scenario: "",
            task: "",
            step: "",
            action: step.description,
            image: step.image ? step.image : "",
            errors: step.errors.map((err) => ({
              ...err,
              highLightColor: scr.highLightColor || "red",
            })),
            imageHeight: step.imageHeight,
            imageWidth: step.imageWidth,
          };

          const impactLevelsData = wcagHelper.useImpactLevelData(step);

          item = { ...item, ...impactLevelsData };

          // let sum = Object.values(impactLevelsData).reduce(
          //   (a, b) => a + b,
          //   0
          // );
          // item.totalIssues = sum;
          item.totalIssuesArray = impactLevelsData;

          scriptItemData.push(item);
        });
      });
    });
  });

  scriptItems.value = JSON.parse(JSON.stringify(scriptItemData));
};

const addCategoryIssues = (isLoadedOnMounted) => {
  scripts.value.forEach((scr) => {
    const sumOfCategoriesForScript = wcagHelper.useSumOfCategoriesForScript(
      scr,
      scriptItems.value
    );
    let scriptSum = 0;
    const scriptIndex = scriptItems.value.findIndex((i) => i.id === scr.id);
    if (scriptIndex !== -1) {
      Object.keys(sumOfCategoriesForScript).forEach((key) => {
        scriptItems.value[scriptIndex][key] = sumOfCategoriesForScript[key];
        scriptSum += sumOfCategoriesForScript[key];
      });
      // scriptItems.value[scriptIndex].totalIssues = scriptSum;
      scriptItems.value[scriptIndex].totalIssues =
        sumOfCategoriesForScript.wcag2aaa +
        sumOfCategoriesForScript.miscellaneous;
      scriptItems.value[scriptIndex].totalIssuesArray =
        sumOfCategoriesForScript;
    }

    scr.scenarios.forEach((scn) => {
      const sumOfCategoriesForScenario =
        wcagHelper.useSumOfCategoriesForScenario(scn, scriptItems.value);
      let scenarioSum = 0;
      const scenarioIndex = scriptItems.value.findIndex((i) => i.id === scn.id);
      if (scenarioIndex !== -1) {
        Object.keys(sumOfCategoriesForScenario).forEach((key) => {
          scriptItems.value[scenarioIndex][key] =
            sumOfCategoriesForScenario[key];
          scenarioSum += sumOfCategoriesForScenario[key];
        });
        // scriptItems.value[scenarioIndex].totalIssues = scenarioSum;
        scriptItems.value[scenarioIndex].totalIssues =
          sumOfCategoriesForScenario.wcag2aaa +
          sumOfCategoriesForScenario.miscellaneous;
        scriptItems.value[scenarioIndex].totalIssuesArray =
          sumOfCategoriesForScenario;
      }

      scn.activities.forEach((act) => {
        const sumOfActionsForCategories =
          wcagHelper.useSumOfActionsForCategories(act, scriptItems.value);

        let activitySum = 0;
        const activityIndex = scriptItems.value.findIndex(
          (i) => i.id === act.id
        );
        if (activityIndex !== -1) {
          Object.keys(sumOfActionsForCategories).forEach((key) => {
            scriptItems.value[activityIndex][key] =
              sumOfActionsForCategories[key];
            activitySum += sumOfActionsForCategories[key];
          });
          // scriptItems.value[activityIndex].totalIssues = activitySum;
          scriptItems.value[activityIndex].totalIssues =
            sumOfActionsForCategories.wcag2aaa +
            sumOfActionsForCategories.miscellaneous;
          scriptItems.value[activityIndex].totalIssuesArray =
            sumOfActionsForCategories;
        }
      });
    });
  });
};

const showErrors = async (image, errorsArr, item, filterKey) => {
  actionName.value = item.action;
  errorDialog.value = true;

  if (filterKey && filterKey !== "totalIssues") {
    errors.value = errorsArr.filter((e) => {
      if (filterKey === "wcag2a" || filterKey === "miscellaneous") {
        return e.accessibilityCategory === filterKey;
      }
      if (filterKey === "wcag2aa") {
        return (
          e.accessibilityCategory === "wcag2a" ||
          e.accessibilityCategory === "wcag2aa"
        );
      }
      if (filterKey === "wcag2aaa") {
        return ["wcag2a", "wcag2aa", "wcag2aaa"].includes(
          e.accessibilityCategory
        );
      }
    });

    errorsExpansionPanel.value = errors.value.map((e, i) => i);
    isAllExpanded.value = true;
  } else {
    errors.value = errorsArr;
    errorsExpansionPanel.value = [];
    isAllExpanded.value = false;
  }

  baseImage.value = image;
  dimension.value = await commonHelper.getDimensions(image);
  imageHeight.value = item.imageHeight;
  imageWidth.value = item.imageWidth;
};

const openAllCloseAllToggle = () => {
  if (isAllExpanded.value) {
    errorsExpansionPanel.value = [];
  } else {
    errorsExpansionPanel.value = errors.value.map((e, i) => i);
  }

  isAllExpanded.value = !isAllExpanded.value;
};

const expandImage = (rect, highLightColor) => {
  imageDialog.value = true;
  rectangleHighlightColor.value = highLightColor;
  rectangle = rect;
};
const trimScriptName = (name) => (name ? name.split(".")[0] : "");

const displaySepratedByComma = (data) =>
  data && data.length != 1 ? data.join(", ") : data;

const filterBySelectedImpacts = () => {
  if (copyOfScript.value) {
    let scriptsData = JSON.parse(JSON.stringify(copyOfScript.value));
    let countToCalculateAccessbilityLength = 0;

    scriptsData = scriptsData.filter((script) => {
      script.scenarios = script.scenarios.filter((scenario) => {
        scenario.activities = scenario.activities.filter((activity) => {
          activity.accessibilityData = activity.accessibilityData.filter(
            (accessibilityData) => {
              accessibilityData.errors = accessibilityData.errors.filter(
                (errors) => {
                  // return selectedImpacts.value.indexOf(errors.impact) > -1;
                  return (
                    selectedImpacts.value.indexOf(
                      errors.accessibilityCategory
                    ) > -1
                  );

                  // const wcagCat = ['wcag2a', 'wcag2aa', 'wcag2aaa'];
                  // return selectedImpacts.value.some(ele => errors.tags.includes(ele)) || wcagCat.every(e => !errors.tags.includes(e));
                }
              );
              return accessibilityData.errors.length > 0 ? true : false;
            }
          );

          if (activity.accessibilityData.length > 0) {
            countToCalculateAccessbilityLength++;
          }
          return activity.accessibilityData.length > 0 ? true : false;
        });
        return scenario.activities.length > 0 ? true : false;
      });
      return script.scenarios.length > 0 ? true : false;
    });

    displayWarningMessage.value =
      countToCalculateAccessbilityLength == 0 ? true : false;

    mapScriptData(scriptsData);
    createTableData();
    addCategoryIssues();

    let allImpacts = impact.value.map((item) => item.value);
    headers.value = headers.value.filter((item) => {
      return allImpacts.indexOf(item.key) > -1
        ? selectedImpacts.value.indexOf(item.key) > -1
        : true;
    });
  }
};

const toggleInAccessbility = () => {
  nextTick(() => {
    let impactValues = impact.value.map((item) => item.value);
    if (selectedAllImpacts.value) {
      selectedImpacts.value = [];
    } else {
      selectedImpacts.value = impactValues.slice();
    }
  });
};

const setLinks = (text) => {
  const Rexp =
    /(\b(https?|ftp|file):\/\/([-A-Z0-9+&@#%?=~_|!:,.;]*)([-A-Z0-9+&@#%?/=~_|!:,.;]*)[-A-Z0-9+&@#/%=~_|])/gi;
  return text.replace(Rexp, "<a href='$1' target='_blank'>$1</a>");
};

const showHelpInfo = (errNodes) => {
  helpDialog.value = true;
  console.log(errNodes);
  detail.value = errNodes[0].aiDetail;
  suggestion.value = errNodes[0].aiSuggestion;
};
</script>

