      doc.addPage();
      generateAccessibilityMobilePage(doc, item);
    }
    if (personaObject.accessibilityAndroid) {
      doc.addPage();
      generateAccessibilityAndroidMobileAppPage(doc, item);
    }
    if (personaObject.qumPerformance) {
      doc.addPage();
      generatePerformancePage(doc, item);
    }
    if (personaObject.browserPerformance) {
      doc.addPage();
      generateBrowserPage(doc, item);
