const createTableDataForFeatureSummary = (persona, tableData) => {
  const personaObject = window[persona.name];
  const featuresData = summaryHelper.getMetricDataList(
    personaObject,
    "features"
  );
  const featureTableData = {
    scenarios: featuresData.length,
    tasks: summaryHelper.getSumOfScenarios(featuresData),
    steps: summaryHelper.getSumOfTasks(featuresData),
    actions: summaryHelper.getSumOfActions(featuresData),
  };
  const { scenarios, tasks, steps, actions } = featureTableData;

  tableData[0].push(scenarios);
  tableData[1].push(tasks);
  tableData[2].push(steps);
  tableData[3].push(actions);
};

const createTableDataForWCAGSummary = (persona, tableData) => {
  const personaObject = window[persona.name];
  if (personaObject.accessibility) {
    const accessibilityData = summaryHelper.getMetricDataList(
      personaObject,
      "accessibility"
    );
    const tasks = summaryHelper.getSumOfScenarios(accessibilityData);
    const wcaga = Math.round(
      summaryHelper.getAvgNoOfViolations(accessibilityData, "wcag2a", tasks)
    );
    const wcagaa = Math.round(
      summaryHelper.getAvgNoOfViolations(accessibilityData, "wcag2aa", tasks)
    );
    const wcagaaa = Math.round(
      summaryHelper.getAvgNoOfViolations(accessibilityData, "wcag2aaa", tasks)
    );

    const accessibilityTableData = {
      tasks: tasks,
      // seriousViolations: Math.round(summaryHelper.getAvgNoOfViolations(
      //   accessibilityData,
      //   "serious",
      //   tasks
      // )),
      // criticalViolations: Math.round(summaryHelper.getAvgNoOfViolations(
      //   accessibilityData,
      //   "critical",
      //   tasks
      // )),
      // moderateViolations: Math.round(summaryHelper.getAvgNoOfViolations(
      //   accessibilityData,
      //   "moderate",
      //   tasks
      // )),
      // minorViolations: Math.round(summaryHelper.getAvgNoOfViolations(
      //   accessibilityData,
      //   "minor",
      //   tasks
      // )),
      wcagACount: wcaga,
      wcagAACount: wcaga + wcagaa,
      wcagAAACount: wcaga + wcagaa + wcagaaa,
      miscellaneousCount: Math.round(
        summaryHelper.getAvgNoOfViolations(
          accessibilityData,
          "miscellaneous",
          tasks
        )
      ),
    };
    const { wcagACount, wcagAACount, wcagAAACount, miscellaneousCount } =
      accessibilityTableData;

    tableData[0].push(tasks);
    tableData[1].push(wcagACount);
    tableData[2].push(wcagAACount);
    tableData[3].push(wcagAAACount);
    tableData[4].push(miscellaneousCount);
    tableData[5].push(
      wcagHelper.useConformanceLevel(wcagACount, wcagAACount, wcagAAACount)
    );
  } else {
    tableData[0].push("-");
    tableData[1].push("-");
    tableData[2].push("-");
    tableData[3].push("-");
    tableData[4].push("-");
    tableData[5].push("-");
  }
};
