const createTableDataForI18nSummary = (persona, tableData, i18nItems) => {
  const personaObject = window[persona.name];
  if (personaObject.i18N) {
    const i18nData = summaryHelper.getMetricDataList(personaObject, "i18N");
    const sumOfScnearios = summaryHelper.getSumOfScenarios(i18nData);

    const languages = [...new Set(i18nData.map((item) => item.language))];
    const avgViolations = summaryHelper.getAvgViolations(i18nData);

    const i18NReportTableData = {
      tasks: sumOfScnearios,
      languagesSupported: languages,
      avgViolations,
    };

    i18nItems[0][persona.name] = i18NReportTableData.tasks;
    i18nItems[1][persona.name] = i18NReportTableData.languagesSupported;
    for (let index = 2; index < i18nItems.length; index++) {
      if (avgViolations[index - 2]) {
        const elIndex = i18nItems.findIndex((el) =>
          el.name.includes(avgViolations[index - 2].language)
        );
        i18nItems[elIndex][persona.name] = avgViolations[index - 2].violations;
        if (
          !i18nItems[index][persona.name] ||
          i18nItems[index][persona.name] === ""
        ) {
          i18nItems[index][persona.name] = "-";
        }
      } else {
        if (
          !i18nItems[index][persona.name] ||
          i18nItems[index][persona.name] === ""
        ) {
          i18nItems[index][persona.name] = "-";
        }
      }
    }
  } else {
    i18nItems.forEach((_, i) => {
      i18nItems[i][persona.name] = "-";
    });
  }
};

