const createFeatureDataTable = (doc, data) => {
  const headers = featureHelper.useHeaders();

  let tableData = [],
    columns = [],
    scriptItems = [];
  data.forEach((scr) => {
    const script = {
      scenario: useTrimScriptName(scr.scriptName),
      scenariosCount: scr.scenarios.length,
      task: scr.scenarios.length,
      step: metricsHelper.useSumOfTasks(scr),
      action: metricsHelper.useSumOfActions(scr),
    };
    scriptItems.push(script);

    scr.scenarios.forEach((scn) => {
      const scenario = {
        scenario: "",
        task: scn.scenarioName,
        step: scn.activities.length,
        action: metricsHelper.useSumOfActionsForScenario(scn),
      };
      scriptItems.push(scenario);

      scn.activities.forEach((act) => {
        const activity = {
          scenario: "",
          task: "",
          step: act.activityName,
          action: act.actionMessagesList.length,
        };
        scriptItems.push(activity);

        act.actionMessagesList.forEach(async (msg) => {
          let item = {
            scenario: "",
            task: "",
            step: "",
            action: msg.insightMessage,
          };
          scriptItems.push(item);
        });
      });
    });
  });

  scriptItems.forEach((item) => {
    const { scenario, task, step, action } = item;
    tableData.push([scenario, task, step, action]);
  });
  headers.forEach((item) => {
    const { title, key } = item;
    columns.push({ header: title, dataKey: key });
  });

  autoTable(doc, {
    head: [headers.map((header) => header.title)],
    body: tableData,
    columns: columns,
    columnStyles: {
      scenario: { cellWidth: 180 },
    },
    ...dataTableConfig,
    willDrawPage: (data) => createPDFHeader(doc, data),
    didDrawPage: (data) => createPDFFooter(doc, data),
  });
};

