const createPeformanceSummaryTable = (doc, data, persona) => {
  doc.setFontSize(12);
  doc.setFont(undefined, "bold");
  doc.text("Summary", 40, 80);

  let summaryColumns = [],
    categoryColumns = [];
  let tasks = 0,
    steps = 0,
    actions = 0;
  data.forEach((script) => {
    tasks += script.scenarios.length;
    script.scenarios.forEach((scenario) => {
      steps += scenario.activities.length;
      scenario.activities.forEach((activity) => {
        actions += activity.actionMessagesList.length;
      });
    });
  });
  let userActionTime = 0,
    systemDelay = 0,
    totalTime = 0,
    networkCalls = 0;

  data.forEach((scr) => {
    scr.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.actionMessagesList.forEach((item) => {
          userActionTime = userActionTime + item.userActionTime;
          systemDelay = systemDelay + item.systemDelay;
          totalTime = parseFloat(userActionTime) + parseFloat(systemDelay);
          networkCalls = networkCalls + item.networkEntries.length;
        });
      });
    });
  });

  const summaryHeaders = [
    { text: "Name", value: "name" },
    { text: "Persona", value: "persona" },
    { text: "Tasks", value: "scenarios" },
    { text: "Scenarios", value: "tasks" },
    { text: "Steps", value: "steps" },
    { text: "Actions", value: "actions" },
  ];

  const categoryHeaders = [
    { text: "Categories", value: "categories" },
    { text: "Values", value: "values" },
  ];

  summaryHeaders.forEach((item) => {
    const { text, value } = item;
    summaryColumns.push({ header: text, dataKey: value });
  });
  categoryHeaders.forEach((item) => {
    const { text, value } = item;
    categoryColumns.push({ header: text, dataKey: value });
  });

  const summaryData = [
    ["Name", window.info[0].applicationName],
    ["Persona", persona],
    ["Tasks", data.length],
    ["Scenarios", tasks],
    ["Steps", steps],
    ["Actions", actions],
  ];
  const categoryData = [
    ["User Action Time", useMillisecondsToStr(userActionTime)],
    ["System Delay", useMillisecondsToStr(systemDelay)],
    ["Total Time", useMillisecondsToStr(totalTime)],
    ["Network Calls", networkCalls],
  ];
  var pageSize = doc.internal.pageSize;
  var pageWidth = pageSize.width;
  autoTable(doc, {
    body: summaryData,
    columns: [
      { dataKey: "id", header: "ID" },
      { dataKey: "name", header: "Name" },
    ],
    ...summaryTableConfig,
    tableWidth: pageWidth / 2 - 80,
    margin: { left: 40 },
    showHead: "never",
  });

  autoTable(doc, {
    head: [categoryHeaders.map((header) => header.text)],
    body: categoryData,
    columns: categoryColumns,
    tableWidth: pageWidth / 2 - 20,
    margin: { left: pageWidth / 2 - 20 },
    headStyles: {
      fillColor: [255, 255, 255],
      textColor: [0, 0, 0],
      fontStyle: "bold",
    },
    ...summaryTableConfig,
  });
};

