const createBrowserTableDataForPDF = (data) => {
  pdf.browser.scenarios = [];
  data.forEach((script) => {
    script.scenarios.forEach((scn) => {
      let actItems = [];
      scn.activities.forEach((act) => {
        act.browserPerformanceList.forEach((step) => {
          let item = {};
          const {
            description,
            TTFB,
            TTLB,
            domInteractive,
            contentDownload,
            firstInteractive,
            firstResponseTime,
            latency,
            networkOverhead,
            pageCompleteTime,
            pageReady,
            onLoad,
            domContentLoaded,
            backEndTime,
          } = step;

          item = {
            description,
            ttfb: TTFB,
            ttlb: TTLB,
            domInteractive,
            pageCompleteTime,
            latency,
            networkOverhead,
            firstResponseTime,
            contentDownload,
            firstInteractive,
            pageReady,
            onLoad,
            domContentLoaded,
            backEndTime,
          };

          item.contentDownload = useMillisecondsToStr(item.contentDownload);
          item.domInteractive = useMillisecondsToStr(item.domInteractive);
          item.firstInteractive = useMillisecondsToStr(item.firstInteractive);
          item.firstResponseTime = useMillisecondsToStr(item.firstResponseTime);
          item.latency = useMillisecondsToStr(item.latency);
          item.networkOverhead = useMillisecondsToStr(item.networkOverhead);
          item.pageCompleteTime = useMillisecondsToStr(item.pageCompleteTime);
          item.pageReady = useMillisecondsToStr(item.pageReady);
          item.ttfb = useMillisecondsToStr(item.ttfb);
          item.ttlb = useMillisecondsToStr(item.ttlb);
          item.onLoad = useMillisecondsToStr(item.onLoad);
          item.domContentLoaded = useMillisecondsToStr(item.domContentLoaded);
          item.backEndTime = useMillisecondsToStr(item.backEndTime);
          actItems.push(item);
        });
      });
      pdf.browser.scenarios.push({
        script: script.scriptName.split(".")[0],
        name: scn.scenarioName,
        activities: actItems,
      });
    });
  });

  computedBrowserHeadersForPDF();
};

const computedBrowserHeadersForPDF = () => {
  pdf.browser.headers = [
    { text: "Description", value: "description" },
    { text: "TTFB", value: "ttfb" },
    { text: "TTLB", value: "ttlb" },
    { text: "Dom Interactive", value: "domInteractive" },
    { text: "Page Complete Time", value: "pageCompleteTime" },
    { text: "Network Latency", value: "latency" },
    { text: "Network Overhead", value: "networkOverhead" },
    { text: "First Response", value: "firstResponseTime" },
    { text: "On Load", value: "onLoad" },
    { text: "DOM Content Download", value: "domContentLoaded" },
    { text: "Content Download", value: "contentDownload" },
    { text: "First Interactive", value: "firstInteractive" },
    { text: "Page Ready", value: "pageReady" },
    { text: "Back End time", value: "backEndTime" },
  ];

  pdf.browser.scenarios.forEach((scn) => {
    scn.activities.forEach((act) => {
      const step = act;
      // remove keys that are not present in the object
      Object.keys(step).forEach((key) => {
        step[key] === undefined || step[key] === "" || step[key] === "NaNs"
          ? delete step[key]
          : {};
      });

      const keys = Object.keys(step);

      const res = pdf.browser.headers.filter((item) =>
        keys.includes(item.value)
      );
      pdf.browser.headers = res;
    });
  });
};

