const createI18NSummaryDataForPDF = (data, persona) => {
  const scripts = data.map((scr) => {
    return {
      name: scr.scriptName ? scr.scriptName.split(".")[0] : "",
      language: scr.language,
      scenariosCount: scr.scenarios.length,
      activitiesCount: metricsHelper.useSumOfTasks(scr),
      tasks: metricsHelper.useSumOfTasks(scr),
      actions: metricsHelper.useSumOfActions(scr, "i18N"),
      wordCount: i18NHelper.getScriptWordCount(scr),
      altWordCount: i18NHelper.getAltWordCountForScript(scr),
      ariaLabelWordCount: i18NHelper.getAriaLabelWordCountForScript(scr),
      toolTipWordCount: i18NHelper.getTooltipWordCountForScript(scr),
      titleWordCount: i18NHelper.getTitleWordCountForScript(scr),
      scenarios: scr.scenarios,
    };
  });

  let totalTasks = 0,
    totalActions = 0,
    totalAltWordCount = 0,
    totalAriaLabelWordCount = 0,
    totalToolTipWordCount = 0,
    totalTitleWordCount = 0,
    totalContentWordCount = 0,
    totalSteps = 0,
    totalIssues = 0;
  scripts.forEach((script) => {
    totalTasks += script.tasks;
    totalActions += script.actions;
    totalAltWordCount += script.altWordCount;
    totalAriaLabelWordCount += script.ariaLabelWordCount;
    totalToolTipWordCount += script.toolTipWordCount;
    totalTitleWordCount += script.titleWordCount;
    totalContentWordCount += script.wordCount;
    script.scenarios.forEach((scenario) => {
      totalSteps += scenario.activities.length;
    });
  });

  totalIssues =
    totalAltWordCount +
    totalAriaLabelWordCount +
    totalToolTipWordCount +
    totalTitleWordCount +
    totalContentWordCount;

  const summaryData = [
    ["Name", window.info[0].applicationName],
    ["Persona", persona],
    [
      "Target Language",
      [...new Set(data.map((scr) => scr.language))].join(", "),
    ],
    ["Tasks", data.length],
    ["Scenarios", totalTasks],
    ["Steps", totalSteps],
    ["Actions", totalActions],
  ];

  const categoryData = [
    ["Content", totalContentWordCount],
    ["Title", totalTitleWordCount],
    ["Aria Label", totalAriaLabelWordCount],
    ["Tooltip", totalToolTipWordCount],
    ["Alt", totalAltWordCount],
    ["Total", totalIssues],
  ];
  return { summaryData, categoryData };
};

