      summaryHelper.getSecurityIssuesAsPerCategoryScript(scr, "Informational");
    let falsePositiveCountForScript =
      summaryHelper.getSecurityIssuesAsPerCategoryScript(scr, "False Positive");
    let totalCountForScript =
      highCountForScript +
