        let mediumCountforActivity =
          summaryHelper.getSecurityIssuesAsPerCategoryActivity(act, "Medium");
        let lowCountforActivity =
          summaryHelper.getSecurityIssuesAsPerCategoryActivity(act, "Low");
        let informationalCountforActivity =
          summaryHelper.getSecurityIssuesAsPerCategoryActivity(
            act,
            "Informational"
          );
        let falsePositiveCountforActivity =
          summaryHelper.getSecurityIssuesAsPerCategoryActivity(
            act,
            "False Positive"
          );
        let totalCountForActivity =
          highCountforActivity +
          mediumCountforActivity +
          lowCountforActivity +
          informationalCountforActivity +
          falsePositiveCountforActivity;
        const activity = {
          id: act.id,
          scenario: "",
          task: "",
          step: act.activityName,
          action: act.vulnerability.length,
          high: highCountforActivity,
          medium: mediumCountforActivity,
          low: lowCountforActivity,
          informational: informationalCountforActivity,
          falsePositive: falsePositiveCountforActivity,
          total: totalCountForActivity,
        };
        scriptItemData.push(activity);

        act.vulnerability.forEach((step) => {
          let highCountForStep =
            summaryHelper.getSecurityIssuesAsPerCategoryAction(step, "High");
          let mediumCountForStep =
            summaryHelper.getSecurityIssuesAsPerCategoryAction(step, "Medium");
          let lowCountForStep =
            summaryHelper.getSecurityIssuesAsPerCategoryAction(step, "Low");
          let informationalCountForStep =
            summaryHelper.getSecurityIssuesAsPerCategoryAction(
              step,
              "Informational"
            );
          let falsePositiveCountForStep =
            summaryHelper.getSecurityIssuesAsPerCategoryAction(
              step,
              "False Positive"
            );
          let totalCountForStep =
            highCountForStep +
            mediumCountForStep +
            lowCountForStep +
            informationalCountForStep +
            falsePositiveCountForStep;
          let item = {
            id: step.id,
            scenario: "",
            task: "",
            step: "",
            high: highCountForStep,
            medium: mediumCountForStep,
            low: lowCountForStep,
            informational: informationalCountForStep,
            falsePositive: falsePositiveCountForStep,
            total: totalCountForStep,
            action: step.insightMessage,
            errors: step.data.site.flatMap((st) => {
              return st.alerts.map((alt) => {
                return { ...alt, siteName: st.name };
              });
            }),
          };

          const impactLevelsData =
            vulenerabilityHelper.useImpactLevelData(step);
          item = { ...item, ...impactLevelsData };
          item.totalIssuesArray = impactLevelsData;
          scriptItemData.push(item);
        });
      });
    });
  });
  pdf.vulnerability.items = scriptItemData;
};

const getWidthOfPDFHeaderImage = (headerImage) => {
  const image = new Image();
  image.onload = function () {
    // This is max height of image which can fit in the header, according to this we need to find accurate width
    const fixedImageHeight = 22;

    props.pdfHeaderImageWidth = (this.width * fixedImageHeight) / this.height;
  };

  image.src = headerImage;
};

const createPDFHeader = (doc, data) => {
  const pageSize = doc.internal.pageSize;
  const pageWidth = pageSize.width;

  const fontSize = 20;
  doc.setFontSize(fontSize);
  doc.setFont(undefined, "normal");
  doc.setTextColor(40);

  const pdfTitle = props.headerTitle || "Quantitative User Metrics";
  doc.text(pdfTitle, data.settings.margin.left, 22);
  const headerTxtWidth =
    (doc.getStringUnitWidth(pdfTitle) * fontSize) / doc.internal.scaleFactor;

  if (window.header && window.header[0] && window.header[0].headerImage) {
    const headerImage = window.header[0].headerImage;
    doc.addImage(
      headerImage,
      "",
      data.settings.margin.left + headerTxtWidth + 10,
      5,
      props.pdfHeaderImageWidth,
      22
    );
  }

  doc.line(
    data.settings.margin.left,
    30,
    pageWidth - data.settings.margin.right,
    30
  );
};

const createPDFFooter = (doc, data) => {
  const pageSize = doc.internal.pageSize;
  const pageWidth = pageSize.width;
  const pageHeight = pageSize.height ? pageSize.height : pageSize.getHeight();
  doc.line(
    data.settings.margin.left,
    pageHeight - 30,
    pageWidth - data.settings.margin.right,
    pageHeight - 30
  );
  doc.setFont(undefined, "normal");
  doc.setFontSize(10);
  doc.text(
    "© Copyright 2024 Accion Labs | All Rights Reserved",
    data.settings.margin.left,
    pageHeight - 10
  );

  doc.text("Powered by", pageWidth - 160, pageHeight - 10);
  const accionLogo = logoImages.base64.accionLogo;
  doc.addImage(accionLogo, "", pageWidth - 110, pageHeight - 35, 98.5, 30);
};

const getUniqueLanguages = () => {
  i18NLanguages = []; // clear the existing languages first

  props.selectedPersonas.forEach((item) => {
    if (item.name === "All Personas") return;

    const persona = item.name;
    const personaObject = window[persona];
    if (personaObject.i18N) {
      const i18nData = summaryHelper.getMetricDataList(personaObject, "i18N");
      const languages = i18nData.map((item) => item.language);
      i18NLanguages = [...languages, ...i18NLanguages];
    }
  });
  return [...new Set(i18NLanguages)];
};
