<template>
  <div class="features-tab">
    <div class="my-8">
      <div class="text-left my-1">
        <h2 class="heading fontColor text-left">{{ props.tabObject.header }}</h2>
      </div>
      <v-divider></v-divider>
      <v-card class="summary-card" width="50%">
        <v-card-title class="font-weight-bold left text-left">Summary</v-card-title>
        <v-card-text>
          <v-table>
            <template v-slot:default>
              <tbody>
                <tr v-for="item in data" :key="item.name">
                  <td class="subtitle1">{{ item.name }}</td>
                  <td>{{ item.value }}</td>
                </tr>
              </tbody>
            </template>
          </v-table>
        </v-card-text>
      </v-card>
      <v-divider></v-divider>
      <v-data-table-virtual :headers="headers" :items="items" disable-pagination class="elevation-1 featureTable"
        hide-default-footer fixed-header>
      </v-data-table-virtual>
    </div>
  </div>
</template>

<script setup>

import { ref, onMounted, watch } from 'vue'
import { v4 as uuidv4 } from 'uuid';
import useMetricsHelper from '../../use/useMetricsHelper.js';
import useFeatureHelper from '../../use/useFeatureHelper.js';
import useCommonHelper from '../../use/useCommonHelper.js' // Assuming featureHelper is a separate file
const scripts = ref([])
const headers = ref([])
const featureListData = ref([])
const items = ref([])
const data = ref([])
const persona = ref("")
const uuid = ref("")

const props = defineProps(['tabObject']);
const metricsHelper = useMetricsHelper();
const featureHelper = useFeatureHelper();
const { useTrimScriptName } = useCommonHelper();

watch(() => props.tabObject, (newVal) => {
  if (newVal.componentName === "FeatureTab") {
    featureListData.value = newVal.data.qumDataList;
    persona.value = newVal.data.persona;
    initialiseUI();
  }
})

onMounted(() => {
  setUUID();
  featureListData.value = props.tabObject.data.qumDataList;
  persona.value = props.tabObject.data.persona;
  initialiseUI();
});

const setUUID = () => { uuid.value = uuidv4() }

const createSummary = () => {
  let tasks = 0,
    steps = 0,
    actions = 0;
  scripts.value.forEach((script) => {
    tasks += script.scenarios.length;
    script.scenarios.forEach((scenario) => {
      steps += scenario.activities.length;
      scenario.activities.forEach((activity) => {
        actions += activity.actionMessagesList.length;
      });
    });
  });

  data.value = [
    {
      name: "Name",
      value: window.info[0].applicationName,
    },
    {
      name: "Persona",
      value: persona.value,
    },
    {
      name: "Tasks",
      value: scripts.value.length,
    },
    {
      name: "Scenarios",
      value: tasks,
    },
    {
      name: "Steps",
      value: steps,
    },
    {
      name: "Actions",
      value: actions,
    },
  ];

}

const createTableData = () => {
  items.value = [];
  scripts.value.forEach((scr) => {
    const script = {
      id: scr.id,
      scenario: useTrimScriptName(scr.scriptName),
      scenariosCount: scr.scenarios.length,
      task: scr.scenarios.length,
      step: metricsHelper.useSumOfTasks(scr),
      action: metricsHelper.useSumOfActions(scr),
    };

    items.value.push(script);

    scr.scenarios.forEach((scn) => {
      const scenario = {
        id: scn.id,
        scenario: "",
        task: scn.scenarioName,
        step: scn.activities.length,
        action: metricsHelper.useSumOfActionsForScenario(scn),
      };
      items.value.push(scenario);

      scn.activities.forEach((act) => {
        const activity = {
          id: act.id,
          scenario: "",
          task: "",
          step: act.activityName,
          action: act.actionMessagesList.length,
        };
        items.value.push(activity);

        act.actionMessagesList.forEach((msg) => {
          let item = {
            id: msg.id,
            scenario: "",
            task: "",
            step: "",
            action: msg.insightMessage,
          };
          items.value.push(item);
        });
      });
    });
  });
}

const initialiseUI = () => {
  if (featureListData.value) {
    headers.value = featureHelper.useHeaders();
    let scriptTemp = featureListData.value;

    scripts.value = scriptTemp.map((scr) => {
      return {
        id: uuid.value,
        name: scr.scriptName,
        nameOnly: scr.scriptName.split(".")[0],
        ...scr,
        scenarios: scr.scenarios.map((scn) => {
          return {
            id: uuid.value,
            scenarioName: scn.scenarioName,
            ...scn,
            activities: scn.activities.map((act) => {
              return {
                id: uuid.value,
                ...act,
                messages: act.actionMessagesList.map((msg) => {
                  
                  return {
                    id: uuid.value,
                    ...msg,
                  };
                }),
              };
            }),
          };
        }),
      };
    });
    
    createSummary();
    createTableData();
  } else {
    //$router.push({ name: "upload" });
  }


}
</script>


