export function getUserActionTimeForScript(scripts, tasks) {
  let sum = 0;
  scripts.forEach((script) => {
    script.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.actionMessagesList.forEach((item) => {
          sum = sum + item.userActionTime;
        });
      });
    });
  });
  return millisecondsToStr(sum / tasks);
}
