export function getAvgNoOfViolations(scripts, violationCategory, taskLength) {
  let sumOfViolations = 0;
  scripts.forEach((script) => {
    script.scenarios.forEach((activities) => {
      activities.activities.forEach((activity) => {
        activity.accessibilityData.forEach((action) => {
          action.errors.filter((item) => {
            // if (item.impact == violationCategory) {
            //   sumOfViolations = sumOfViolations + item.errNodes.length;
            // }

            if (item.tags.includes("wcag2a")) {
              item["accessibilityCategory"] = "wcag2a";
            } else if (item.tags.includes("wcag2aa")) {
              item["accessibilityCategory"] = "wcag2aa";
            } else if (item.tags.includes("wcag2aaa")) {
              item["accessibilityCategory"] = "wcag2aaa";
            } else {
              item["accessibilityCategory"] = "miscellaneous";
            }
            if (item.accessibilityCategory === violationCategory) {
              sumOfViolations = sumOfViolations + item.errNodes.length;
            }
          });
        });
      });
    });
  });
  return (sumOfViolations / taskLength).toFixed(2);
}
