export function getAvgTimeOfSomeBrowserMetrics(scripts, type, scenariosLength) {
  let sum = 0;
  scripts.forEach((script) => {
    script.scenarios.forEach((scenario) => {
      scenario.activities.forEach((activity) => {
        activity.browserPerformanceList.forEach((browserPerformanceItem) => {
          switch (type) {
            case "page completion":
              sum +=
                browserPerformanceItem.pageCompleteTime == "0.00"
                  ? 0
                  : parseFloat(browserPerformanceItem.pageCompleteTime);
              break;
            case "network latency":
              sum +=
                browserPerformanceItem.latency == "0.00"
                  ? 0
                  : parseFloat(browserPerformanceItem.latency);
              break;
            case "content download":
              sum +=
                browserPerformanceItem.contentDownload == "0.00"
                  ? 0
                  : parseFloat(browserPerformanceItem.contentDownload);
              break;
          }
        });
      });
    });
  });
  if (!isNaN(sum)) {
    const convertIntoSec = sum / 1000;
    return (convertIntoSec.toFixed(4) / scenariosLength).toFixed(2);
  }
  return undefined;
}
