export function getNoOfFontsForScript(scripts, tasks) {
  let uniqueFonts = [];
  scripts.forEach((script) => {
    script.scenarios.forEach((scenario) => {
      scenario.activities.forEach((activity) => {
        activity.designHygieneList.forEach((designHygieneItem) => {
          designHygieneItem.data.typographyData.fontFamily.forEach(
            (fontObj) => {
              if (!uniqueFonts.includes(fontObj.value)) {
                uniqueFonts.push(fontObj.value);
              }
            }
          );
        });
      });
    });
  });
  if (tasks) {
    return (uniqueFonts.length / tasks).toFixed(2);
  } else {
    return uniqueFonts.length;
  }
}
