export function getMetricDataList(persona, metric) {
  return persona[metric].qumDataList;
}
export function getAvgViolations(scripts) {
  let violations = [];
  scripts.forEach((scr) => {
    const sumOfScnearios = scr.scenarios.length;
    const avgViolations =
      getScriptWordCount(scr) +
      getAltWordCountForScript(scr) +
      getAriaLabelWordCountForScript(scr) +
      getTooltipWordCountForScript(scr) +
      getTitleWordCountForScript(scr);

    // check if item exists in violations
    const elIndex = violations.findIndex((el) =>
      el.language.includes(scr.language)
    );
    if (elIndex > -1) {
      violations[elIndex].violations += Math.round(
        avgViolations / sumOfScnearios
      );
    } else {
      violations.push({
        language: scr.language,
        violations: Math.round(avgViolations / sumOfScnearios),
      });
    }
  });
  return violations;
}

export function millisecondsToStr(milliseconds) {
  let temp = (milliseconds / 1000).toFixed(2);
  return `${temp}s`;
}

export function getPersonas(trendChartData) {
  let personas = [];
  trendChartData.forEach((sprintObj) => {
    sprintObj.data.forEach((category) => {
      category.data.forEach((personaObj) => {
        if (!personas.includes(personaObj.persona)) {
          personas.push(personaObj.persona);
        }
      });
    });
  });
  return personas;
}

export function getSecurityIssuesAsPerCategory(scripts, category) {
  let priorityIssuesAndInstances = 0;

  scripts.flatMap((script) =>
    script.scenarios.flatMap((scenario) =>
      scenario.activities.flatMap((activity) =>
        activity.vulnerability.flatMap((vulnerability) =>
          vulnerability.data.site.flatMap((site) =>
            site.alerts.filter((alert) => {
              const alertSplitted = alert.riskdesc.split("(")[0];
              if (alertSplitted.includes(`${category}`)) {
                priorityIssuesAndInstances += alert.instances.length;
              }
            })
          )
        )
      )
    )
  );
  return priorityIssuesAndInstances;
}

