import { ref } from "vue";

export default function useCommonHelper() {
  function useMakeId(length, appendText) {
    let result = ref("");
    let characters = "abcdefghijklmnopqrstuvwxyza";
    let charactersLength = characters.length;
    for (let i = 0; i < length; i++) {
      result.value += characters.charAt(Math.floor(Math.random() * charactersLength));
    }
    if (appendText) {
      return `${appendText}${result.value}`;
    }
    return result.value;
  }

  function useTruncate(text, length) {
    if (text && length) {
      if (text.length > length) {
        return text.substring(0, length) + "...";
      } else {
        return text;
      }
    } else return text;
  }

  function useMillisecondsToStr(milliseconds) {
    let temp = milliseconds / 1000;
    return `${temp.toFixed(2)}s`;
  }

  function useTrimScriptName(name) {
    return name ? name.split(".")[0] : "";
  }

  function useFormatScriptName(name) {
    return name.split(".")[0];
  }

  function removeBodyScroll(val) {
    if(val) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
  }
  
  function getDimensions(image) {
    return new Promise((resolve) => {
      let img = new Image();
      img.src = image;
      img.onload = () => {
        resolve({ width: img.width, height: img.height });
      };
    });
  }

  return {
    useMakeId,
    useTruncate,
    useMillisecondsToStr,
    useTrimScriptName,
    useFormatScriptName,
    removeBodyScroll,
    getDimensions,
  };
}
