import { ref } from "vue";

export default function useWcagHelper() {
  function useSumOfCategoriesForScript(scr, items) {
    let data = ref([]);

    scr.scenarios.forEach((scn) => {
      data.value.push(useSumOfCategoriesForScenario(scn, items));
    });
    return useSumObjectsByKey(...data.value);
  }

  function useSumOfCategoriesForScenario(scn, items, impact) {
    let data = ref([]);

    scn.activities.forEach((act) => {
      data.value.push(useSumOfActionsForCategories(act, items, impact));
    });
    return useSumObjectsByKey(...data.value);
  }

  function useSumOfActionsForCategories(act, items) {
    const impacts = [
      { text: "WCAG-A", value: "wcag2a" },
      { text: "WCAG-AA", value: "wcag2aa" },
      { text: "WCAG-AAA", value: "wcag2aaa" },
      { text: "Miscellaneous", value: "miscellaneous" },
    ];
    let data = ref({});
    const actIndex = items.findIndex((item) => item.id === act.id);

    impacts.forEach((x) => {
      let sum = 0;
      for (
        let index = actIndex + 1;
        index < act.accessibilityData.length + actIndex + 1;
        index++
      ) {
        const element = items[index];
        sum = sum + element[x.value];
        continue;
      }
      data.value[x.value] = sum;
    });
    return data.value;
  }

  function useScriptErrorCount(scr) {
    let errArray = ref([]);
    scr.scenarios.forEach((scn) => {
      errArray.value.push(useScenarioErrorCount(scn));
    });
    return useSumArrays(errArray.value);
  }

  function useScenarioErrorCount(scn) {
    let errArray = ref([]);
    scn.activities.forEach((act) => {
      errArray.value.push(useActivityErrorCount(act));
    });
    return useSumArrays(errArray.value);
  }

  function useActivityErrorCount(act) {
    let errArray = ref([]);
    act.accessibilityData.forEach((step) => {
      errArray.value.push(useStepErrorCount(step));
    });
    return useSumArrays(errArray.value);
  }

  function useStepErrorCount(step) {
    return step.errors.map((err) => {
      return err.errNodes.length;
    });
  }

  function useSumArrays(arrays) {
    return arrays.reduce(
      (acc, array) => acc.map((sum, i) => sum + array[i]),
      new Array(arrays[0].length).fill(0)
    );
  }

  function useImpactLevelData(step) {
    // let obj = ref({
    //   minor: 0,
    //   moderate: 0,
    //   serious: 0,
    //   critical: 0,
    //   miscellaneous : 0
    // });
    let obj = ref({
      wcag2a: 0,
      wcag2aa: 0,
      wcag2aaa: 0,
      miscellaneous: 0,
    });
    step.errors.forEach((err) => {
      // obj.value[err.impact] = obj.value[err.impact] + err.errNodes.length;

      obj.value[err.accessibilityCategory] =
        obj.value[err.accessibilityCategory] + err.errNodes.length;

      // if(err.tags.includes('wcag2a')) {
      //   obj.value.wcag2a = obj.value.wcag2a + err.errNodes.length;
      // }
      // if(err.tags.includes('wcag2a') || err.tags.includes('wcag2aa')) {
      //   obj.value.wcag2aa = obj.value.wcag2a + obj.value.wcag2aa + err.errNodes.length;
      // }
      //  if(err.tags.includes('wcag2aa') || err.tags.includes('wcag2aa') || err.tags.includes('wcag2aaa')) {
      //   obj.value.wcag2aaa = obj.value.wcag2aaa + err.errNodes.length;
      // }
      //  else {
      //   obj.value.miscellaneous = obj.value.miscellaneous + err.errNodes.length;
      // }
    });

    // return obj.value;

    const wcagCategories = {
      wcag2a: obj.value.wcag2a,
      wcag2aa: obj.value.wcag2a + obj.value.wcag2aa,
      wcag2aaa: obj.value.wcag2a + obj.value.wcag2aa + obj.value.wcag2aaa,
      miscellaneous: obj.value.miscellaneous,
    }

    return {
      wcag2a: wcagCategories.wcag2a,
      wcag2aa: wcagCategories.wcag2aa,
      wcag2aaa: wcagCategories.wcag2aaa,
      miscellaneous: wcagCategories.miscellaneous,
      totalIssues: wcagCategories.wcag2aaa + wcagCategories.miscellaneous,
    };
  }

  function useSumObjectsByKey(...objs) {
    return objs.reduce((a, b) => {
      for (let k in b) {
        // if (b.hasOwnProperty(k)) a[k] = (a[k] || 0) + b[k];
        a[k] = (a[k] || 0) + b[k];
      }
      return a;
    }, {});
  }

  function useConformanceLevel(wcag2a, wcag2aa, wcag2aaa) {
    if (wcag2a === 0 && wcag2aa === 0 && wcag2aaa === 0) {
      return "WCAG-AAA verified";
    } else if (wcag2a === 0 && wcag2aa === 0) {
      return "WCAG-AA verified";
    } else if (wcag2a === 0) {
      return "WCAG-A verified";
    } else {
      return "Not Met";
    }
  }

  return {
    useSumOfCategoriesForScript,
    useSumOfCategoriesForScenario,
    useSumOfActionsForCategories,
    useScriptErrorCount,
    useScenarioErrorCount,
    useActivityErrorCount,
    useStepErrorCount,
    useSumArrays,
    useImpactLevelData,
    useSumObjectsByKey,
    useConformanceLevel,
  };
}
