import useMetricsHelper from './useMetricsHelper.js';
import useCommonHelper from './useCommonHelper.js';

export default function usePerformanceHelper() {
  const metricsHelper = useMetricsHelper();
  const commonHelper = useCommonHelper();

  function getScriptObj(scr) {
    const name = scr.name || scr.scriptName;
    return {
      scenario: commonHelper.useFormatScriptName(name),
      task: scr.scenarios.length,
      step: metricsHelper.useSumOfTasks(scr),
      action: metricsHelper.useSumOfActions(scr),
      actualAction: getSumOfActualActions(scr),
      validity: getScriptValidity(scr),
      outcome: getScriptOutcome(scr),
      userActionTime: getUserActionTimeForScript(scr),
      systemDelay: getSystemDelayForScript(scr),
      totalTime: getTotalTimeForScript(scr),
      networkCalls: getNetworkCallsForScript(scr),
      brokenResources: getBrokenResourcesForScript(scr),
    };
  }

  function getScenarioObj(scn) {
    const name = scn.name || scn.scenarioName;
    return {
      scenario: "",
      task: name,
      step: scn.activities.length,
      action: metricsHelper.useSumOfActionsForScenario(scn),
      actualAction: getActualActionsInScenario(scn),
      validity: getScenarioValidity(scn),
      userActionTime: getUserActionTimeForScenario(scn),
      systemDelay: getSystemDelayForScenario(scn),
      totalTime: getTotalTimeForScenario(scn),
      outcome: getScenarioOutcome(scn),
      networkCalls: getNetworkCallsForScenario(scn),
      brokenResources: getBrokenResourcesForScenario(scn),
    };
  }

  function getActivityObj(act) {
    return {
      scenario: "",
      task: "",
      step: act.activityName,
      action: act.actionMessagesList.length,
      actualAction: act.actionCount,
      validity: checkValidity(act),
      userActionTime: getUserActionTimeForTask(act),
      systemDelay: getSystemDelayForTask(act),
      totalTime: getTotalTimeForTask(act),
      outcome: act.outCome ? "Complete" : "Incomplete",
      networkCalls: getNetworkCallsForTask(act),
      brokenResources: getBrokenResourcesForTask(act),
    };
  }

  function getMessageObj(msg) {
    const brokenResourcesFilterData = msg.networkEntries.filter(
      (e) => e.responseStatus < 200 || e.responseStatus > 299
    );

    return {
      scenario: "",
      task: "",
      step: "",
      action: msg.insightMessage ? msg.insightMessage : "(no message)",
      validity: msg.isPassed ? "Valid" : "Invalid",
      outcome: "-",
      userActionTime: commonHelper.useMillisecondsToStr(msg.userActionTime),
      systemDelay: commonHelper.useMillisecondsToStr(msg.systemDelay),
      totalTime: commonHelper.useMillisecondsToStr(msg.userActionTime + msg.systemDelay),
      networkCalls: msg.networkEntries.length === 0 ? "-" : msg.networkEntries.length,
      brokenResources: brokenResourcesFilterData.length === 0 ? "-" : brokenResourcesFilterData.length,
      networkDetails: msg.networkEntries.length === 0 ? [] : msg.networkEntries,
      brokenResourcesDetails: brokenResourcesFilterData.length === 0 ? [] : brokenResourcesFilterData,
    };
  }

  function getSumOfActualActions(scr) {
    let sum = 0;
    scr.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        sum = sum + act.actionCount;
      });
    });
    return sum;
  }

  function getActualActionsInScenario(scn) {
    let sum = 0;

    scn.activities.forEach((act) => {
      sum = sum + act.actionCount;
    });

    return sum;
  }

  function checkValidity(activity) {
    const isNotPassed = (el) => !el.isPassed;

    if (activity.actionMessagesList.some(isNotPassed)) {
      return "Invalid";
    } else {
      return "Valid";
    }
  }

  function getScenarioValidity(scenario) {
    let result = [];
    scenario.activities.forEach((act) => {
      result.push(checkValidity(act));
    });
    const isNotPassed = (el) => el === "Invalid";

    if (result.some(isNotPassed)) {
      return "Invalid";
    } else {
      return "Valid";
    }
  }

  function getScriptValidity(script) {
    let result = [];
    script.scenarios.forEach((scn) => {
      result.push(getScenarioValidity(scn));
    });

    const isNotPassed = (el) => el === "Invalid";

    if (result.some(isNotPassed)) {
      return "Invalid";
    } else {
      return "Valid";
    }
  }

  function getScenarioOutcome(scenario) {
    const outcome = (el) => !el.outCome;

    if (scenario.activities.some(outcome)) {
      return "Incomplete";
    } else {
      return "Complete";
    }
  }

  function getScriptOutcome(script) {
    let result = [];
    script.scenarios.forEach((scn) => {
      result.push(getScenarioOutcome(scn));
    });

    const outcome = (el) => el === "Incomplete";

    if (result.some(outcome)) {
      return "Incomplete";
    } else {
      return "Complete";
    }
  }

  function getSystemDelayForTask(activity) {
    let sum = 0;
    activity.actionMessagesList.forEach((msg) => {
      sum = sum + msg.systemDelay;
    });
    return commonHelper.useMillisecondsToStr(sum);
  }

  function getUserActionTimeForTask(activity) {
    let sum = 0;
    activity.actionMessagesList.forEach((item) => {
      sum = sum + item.userActionTime;
    });
    return commonHelper.useMillisecondsToStr(sum);
  }

  function getTotalTimeForTask(activity) {
    let sum = 0;
    sum = parseFloat(getUserActionTimeForTask(activity)) + parseFloat(getSystemDelayForTask(activity));
    return `${sum.toFixed(2)}s`;
  }

  function getUserActionTimeForScenario(scenario) {
    let sum = 0;
    scenario.activities.forEach((act) => {
      act.actionMessagesList.forEach((item) => {
        sum = sum + item.userActionTime;
      });
    });
    return commonHelper.useMillisecondsToStr(sum);
  }

  function getUserActionTimeForScript(script) {
    let sum = 0;
    script.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.actionMessagesList.forEach((item) => {
          sum = sum + item.userActionTime;
        });
      });
    });
    return commonHelper.useMillisecondsToStr(sum);
  }

  function getSystemDelayForScenario(scenario) {
    let sum = 0;
    scenario.activities.forEach((act) => {
      act.actionMessagesList.forEach((msg) => {
        sum = sum + msg.systemDelay;
      });
    });
    return commonHelper.useMillisecondsToStr(sum);
  }

  function getTotalTimeForScenario(scenario) {
    let sum = 0;
    sum = parseFloat(getSystemDelayForScenario(scenario)) + parseFloat(getUserActionTimeForScenario(scenario));
    return `${sum.toFixed(2)}s`;
  }

  function getSystemDelayForScript(script) {
    let sum = 0;
    script.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.actionMessagesList.forEach((msg) => {
          sum = sum + msg.systemDelay;
        });
      });
    });
    return commonHelper.useMillisecondsToStr(sum);
  }

  function getTotalTimeForScript(script) {
    let sum = 0;
    sum = parseFloat(getSystemDelayForScript(script)) + parseFloat(getUserActionTimeForScript(script));
    return `${sum.toFixed(2)}s`;
  }

  function getNetworkCallsForTask(activity) {
    let sum = 0;
    activity.actionMessagesList.forEach((msg) => {
      sum = sum + msg.networkEntries.length;
    });

    return sum;
  }

  function getNetworkCallsForScenario(scenario) {
    let sum = 0;
    scenario.activities.forEach((act) => {
      act.actionMessagesList.forEach((msg) => {
        sum = sum + msg.networkEntries.length;
      });
    });
    return sum;
  }

  function getNetworkCallsForScript(script) {
    let sum = 0;
    script.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.actionMessagesList.forEach((msg) => {
          sum = sum + msg.networkEntries.length;
        });
      });
    });
    return sum;
  }

  function getBrokenResourcesForTask(activity) {
    let sum = 0;
    activity.actionMessagesList.forEach((msg) => {
      const filteredRes = msg.networkEntries.filter(
        (e) => e.responseStatus < 200 || e.responseStatus > 299
      );
      sum = sum + filteredRes.length;
    });

    return sum;
  }

  function getBrokenResourcesForScenario(scenario) {
    let sum = 0;
    scenario.activities.forEach((act) => {
      act.actionMessagesList.forEach((msg) => {
        const filteredRes = msg.networkEntries.filter(
          (e) => e.responseStatus < 200 || e.responseStatus > 299
        );
        sum = sum + filteredRes.length;
      });
    });
    return sum;
  }

  function getBrokenResourcesForScript(script) {
    let sum = 0;
    script.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.actionMessagesList.forEach((msg) => {
          const filteredRes = msg.networkEntries.filter(
            (e) => e.responseStatus < 200 || e.responseStatus > 299
          );
          sum = sum + filteredRes.length;
        });
      });
    });
    return sum;
  }

  return {
    getScriptObj,
    getScenarioObj,
    getActivityObj,
    getMessageObj
  };
}
