<template>
  <div class="browser-performance-tab">
    <div>
      <h2 class="text-left">{{ props.tabObject.header }}</h2>
    </div>
    <v-divider></v-divider>

    <div class="summary-container">
      <v-card class="summary-card" width="50%">
        <v-card-title class="text-left">Summary</v-card-title>
        <v-card-text>
          <!-- <v-row>
            <v-col cols="5"> -->
          <v-table>
            <template v-slot:default>
              <tbody>
                <tr v-for="item in data" :key="item.name">
                  <td class="subtitle1">{{ item.name }}</td>
                  <td>{{ item.value }}</td>
                </tr>
              </tbody>
            </template>
          </v-table>
        </v-card-text>
      </v-card>

      <v-card class="pie-chart" width="50%">
        <!-- <div style="height: 320px;"> -->
        <div class="chart-container">
          <highcharts :options="chartOptions" />
        </div>
      </v-card>
    </div>

    <v-divider></v-divider>

    <v-expansion-panels
      multiple
      focusable
      readonly
      v-model="panel"
      class="expansion-panel"
    >
      <v-expansion-panel v-for="(item, i) in scenarios" :key="i">
        <v-expansion-panel-title
          hide-actions
          color="#233e70"
          class="expansion-panel-header"
        >
          <div style="font-size: 18px">
            {{ item.script.split(".")[0] }} / {{ item.name }}
          </div>
        </v-expansion-panel-title>
        <v-expansion-panel-text class="expansion-panel-text">
          <v-data-table-virtual
            :headers="headers"
            :items="item.activities"
            class="browser-metrics-table"
          >
          </v-data-table-virtual>
        </v-expansion-panel-text>
      </v-expansion-panel>
    </v-expansion-panels>
  </div>
</template>

<script setup>
import { ref, onMounted, watch } from "vue";
import chartConfig from "../../config/chart";
import * as summaryHelper from "@/use/summaryHelper";

const props = defineProps(["tabObject"]);

const data = ref([]);
const browserData = ref([]);
const scripts = ref([]);
const scriptName = ref("");
const scriptOnlyName = ref("");
const headers = ref([]);
const scenarios = ref([]);
const panel = ref([]);
const persona = ref("");
const summaryCategories = ref([]);
const pieChartInstance = ref(null);
const chartOptions = ref({});

onMounted(() => {
  browserData.value = props.tabObject.data.qumDataList;
  persona.value = props.tabObject.data.persona;
  initialiseUI();
});

watch(
  () => props.tabObject,
  (newVal) => {
    if (newVal.componentName === "BrowserMetricsTab") {
      browserData.value = newVal.data.qumDataList;
      persona.value = newVal.data.persona;
      initialiseUI();
    }
  }
);

const initialiseUI = () => {
  if (browserData.value) {
    scenarios.value = [];
    // this.actItems = [];
    const scriptsData = browserData.value;
    scripts.value = scriptsData;
    scriptName.value = scripts.value[0].scriptName;
    scriptOnlyName.value = scripts.value[0].scriptName.split(".")[0];
    createSummary();
    createTableData();
  }
};

const createSummary = () => {
  let tasks = 0,
    steps = 0;

  scripts.value.forEach((script) => {
    tasks += script.scenarios.length;
    script.scenarios.forEach((scenario) => {
      steps += scenario.activities.length;
      // scenario.activities.forEach((activity) => {
      //   actions += activity.actionMessagesList.length;
      // });
    });
  });

  data.value = [
    {
      name: "Name",
      value: window.info[0].applicationName,
    },
    {
      name: "Persona",
      value: persona.value,
    },
    {
      name: "Tasks",
      value: scripts.value.length,
    },
    {
      name: "Scenarios",
      value: tasks,
    },
    {
      name: "Steps",
      value: steps,
    },
  ];

  const scenariosLength = summaryHelper.getSumOfScenarios(scripts.value);
  const browserPerfSummData = {
    tasks: scenariosLength,
    avgPageCompletionTime:
      summaryHelper.getAvgTimeOfSomeBrowserMetrics(
        scripts.value,
        "page completion",
        scenariosLength
      ) + "s",
    avgNetworkLatencyTime:
      summaryHelper.getAvgTimeOfSomeBrowserMetrics(
        scripts.value,
        "network latency",
        scenariosLength
      ) + "s",
    avgContentDownloadTime:
      summaryHelper.getAvgTimeOfSomeBrowserMetrics(
        scripts.value,
        "content download",
        scenariosLength
      ) + "s",
  };

  summaryCategories.value = [
    {
      name: "Page Completion",
      y: parseFloat(browserPerfSummData.avgPageCompletionTime),
      color: "#ffe188",
    },
    {
      name: "Network Latency",
      y: parseFloat(browserPerfSummData.avgNetworkLatencyTime),
      color: "#88d567",
    },
    {
      name: "Content Download",
      y: parseFloat(browserPerfSummData.avgContentDownloadTime),
      color: "#b6a3ed",
    },
  ];
  createPieChart();
};

const createPieChart = () => {
  chartOptions.value = {
    ...chartConfig,
    series: [
      {
        name: "Secs",
        colorByPoint: true,
        data: summaryCategories.value,
      },
    ],
  };
};

const createTableData = () => {
  scripts.value.forEach((script) => {
    script.scenarios.forEach((scn) => {
      let actItems = [];
      scn.activities.forEach((act) => {
        act.browserPerformanceList.forEach((step, index) => {
          let item = {};
          const {
            row,
            command,
            description,
            parameters,
            TTFB,
            TTLB,
            domInteractive,
            contentDownload,
            firstInteractive,
            firstResponseTime,
            latency,
            networkOverhead,
            pageCompleteTime,
            pageReady,
            onLoad,
            domContentLoaded,
            backEndTime,
          } = step;

          if (index === 0) {
            item = {
              activity: act.name,
              row,
              command,
              parameters,
              description,
              ttfb: TTFB,
              ttlb: TTLB,
              domInteractive,
              pageCompleteTime,
              latency,
              networkOverhead,
              firstResponseTime,
              contentDownload,
              firstInteractive,
              pageReady,
              onLoad,
              domContentLoaded,
              backEndTime,
            };

            item.contentDownload = millisecondsToStr(item.contentDownload);
            item.domInteractive = millisecondsToStr(item.domInteractive);
            item.firstInteractive = millisecondsToStr(item.firstInteractive);
            item.firstResponseTime = millisecondsToStr(item.firstResponseTime);
            item.latency = millisecondsToStr(item.latency);
            item.networkOverhead = millisecondsToStr(item.networkOverhead);
            item.pageCompleteTime = millisecondsToStr(item.pageCompleteTime);
            item.pageReady = millisecondsToStr(item.pageReady);
            item.ttfb = millisecondsToStr(item.ttfb);
            item.ttlb = millisecondsToStr(item.ttlb);
            item.onLoad = millisecondsToStr(item.onLoad);
            item.domContentLoaded = millisecondsToStr(item.domContentLoaded);
            item.backEndTime = millisecondsToStr(item.backEndTime);

            actItems.push(item);
          } else {
            item = {
              activity: "",
              row,
              command,
              parameters,
              description,
              ttfb: TTFB,
              ttlb: TTLB,
              domInteractive,
              pageCompleteTime,
              latency,
              networkOverhead,
              firstResponseTime,
              contentDownload,
              firstInteractive,
              pageReady,
              onLoad,
              domContentLoaded,
              backEndTime,
            };

            item.contentDownload = millisecondsToStr(item.contentDownload);
            item.domInteractive = millisecondsToStr(item.domInteractive);
            item.firstInteractive = millisecondsToStr(item.firstInteractive);
            item.firstResponseTime = millisecondsToStr(item.firstResponseTime);
            item.latency = millisecondsToStr(item.latency);
            item.networkOverhead = millisecondsToStr(item.networkOverhead);
            item.pageCompleteTime = millisecondsToStr(item.pageCompleteTime);
            item.pageReady = millisecondsToStr(item.pageReady);
            item.ttfb = millisecondsToStr(item.ttfb);
            item.ttlb = millisecondsToStr(item.ttlb);
            item.onLoad = millisecondsToStr(item.onLoad);
            item.domContentLoaded = millisecondsToStr(item.domContentLoaded);
            item.backEndTime = millisecondsToStr(item.backEndTime);
            actItems.push(item);
          }
        });
      });
      scenarios.value.push({
        script: script.scriptName,
        name: scn.scenarioName,
        activities: actItems,
      });
    });
  });

  scenarios.value.forEach((_, index) => {
    panel.value.push(index);
  });

  computedHeaders();
};
const computedHeaders = () => {
  headers.value = [
    { title: "Activity", key: "activity", sortable: false },
    { title: "Description", key: "description", sortable: false },
    { title: "TTFB", key: "ttfb", sortable: false },
    { title: "TTLB", key: "ttlb", sortable: false },
    { title: "Dom Interactive", key: "domInteractive", sortable: false },
    { title: "Page Complete Time", key: "pageCompleteTime", sortable: false },
    { title: "Network Latency", key: "latency", sortable: false },
    { title: "Network Overhead", key: "networkOverhead", sortable: false },
    { title: "First Response", key: "firstResponseTime", sortable: false },
    { title: "On Load", key: "onLoad", sortable: false },
    { title: "DOM Content Download", key: "domContentLoaded", sortable: false },
    { title: "Content Download", key: "contentDownload", sortable: false },
    { title: "First Interactive", key: "firstInteractive", sortable: false },
    { title: "Page Ready", key: "pageReady", sortable: false },
    { title: "Back End time", key: "backEndTime", sortable: false },
  ];

  scenarios.value.forEach((scn) => {
    scn.activities.forEach((act) => {
      const step = act;
      // remove keys that are not present in the object
      Object.keys(step).forEach((key) => {
        step[key] === undefined || step[key] === "" ? delete step[key] : {};
      });

      const keys = Object.keys(step);
      const res = headers.value.filter((item) => keys.includes(item.key));
      headers.value = res;
    });
  });
};
const millisecondsToStr = (milliseconds) => {
  if (milliseconds) {
    let temp = milliseconds / 1000;
    return `${temp.toFixed(2)}s`;
  }
  return "";
};
</script>

