<template>
  <div class="performance-tab">
    <div>
      <div class="performance-heaing">
        <h2>{{ props.tabObject.header }}</h2>
      </div>

      <v-divider></v-divider>

      <div class="summary-container">
        <v-card class="summary-card" width="50%">
          <v-card-title>Summary</v-card-title>
          <v-card-text>
            <v-table>
              <template v-slot:default>
                <tbody>
                  <tr v-for="item in data" :key="item.name">
                    <td class="subtitle1">{{ item.name }}</td>
                    <td>{{ item.value }}</td>
                  </tr>
                </tbody>
              </template>
            </v-table>
          </v-card-text>
        </v-card>

        <v-card class="pie-chart" width="50%">
          <div class="chart-container">
            <highcharts :options="chartOptions" />
          </div>
        </v-card>
      </div>

      <v-divider></v-divider>

      <v-table class="performanceTable">
        <thead>
          <tr>
            <th v-for="head in headers" :key="head.title" :width="head.width">
              {{ head.title }}
            </th>
          </tr>
        </thead>
        <tbody>
          <tr v-for="item in scriptItems" :key="item.id">
            <td
              v-for="headerItem in headers"
              :key="item.id + headerItem.title"
              class="body1"
            >
              <div v-if="headerItem.key === 'validity'">
                <!-- <span :style="{ color: item.validity === 'Valid' ? '#005400' : 'red' }">{{ item.validity }}</span> -->
                <span
                  :class="item.validity === 'Valid' ? 'valid' : 'not-valid'"
                  >{{ item.validity }}</span
                >
              </div>
              <div v-else-if="headerItem.key === 'outcome'">
                <!-- <span :style="{ color: item.outcome === 'Complete' ? '#005400' : 'red' }">{{ item.outcome }}</span> -->
                <span
                  :class="
                    item.outcome === 'Complete' ? 'complete' : 'not-complete'
                  "
                  >{{ item.outcome }}</span
                >
              </div>
              <div v-else-if="headerItem.key === 'userActionTime'">
                <span>{{
                  item.userActionTime ? item.userActionTime : "0s"
                }}</span>
              </div>
              <div v-else-if="headerItem.key === 'systemDelay'">
                <span>{{ item.systemDelay ? item.systemDelay : "0s" }}</span>
              </div>
              <div v-else-if="headerItem.key === 'networkCalls'">
                <div v-if="item.step === ''">
                  <div class="align-center">
                    <span v-if="item.networkCalls === '-'">-</span>
                    <span
                      v-else="item.networkCalls !== '-'"
                      href="#"
                      @click="showNetworkDetails(item)"
                      class="networks_links"
                      >{{ item.networkCalls }}
                    </span>
                  </div>
                </div>
                <div v-else>
                  <span>{{ item.networkCalls }}</span>
                </div>
              </div>
              <div v-else>
                {{ item[headerItem.key] }}
              </div>
            </td>
          </tr>
        </tbody>
      </v-table>
    </div>

    <v-dialog
      v-model="networkDialog"
      class="network-details-dailog"
      content-class="no-dialog-overflow"
      :hide-overlay="hideOverlay"
      fullscreen
      persistent
      max-width="75%"
      aria-label="performance network details"
    >
      <v-card>
        <v-card-title>
          <div class="network-dailog-title">
            <div>{{ networkDialogTitle }}</div>
            <div>
              <div
                class="network-dailog-close-icon"
                @click="networkDialog = false"
              >
                <v-icon icon="mdi mdi-close"></v-icon>
              </div>
            </div>
          </div>
        </v-card-title>
        <v-card-text class="network-dailog-text">
          <v-data-table-virtual
            disable-sort
            :headers="networkHeaders"
            :items="networkData"
            class="network-table"
          >
            <template v-slot:item.name="{ item }">
              <div>
                <a :href="item.name" target="_blank">{{
                  useTruncate(item.name, 100)
                }}</a>
              </div>
            </template>
          </v-data-table-virtual>
        </v-card-text>
