<script setup>
import { ref, onMounted, watch } from "vue";
import chartConfig from "../../config/chart";
import usePerformanceHelper from "../../use/usePerformanceHelper.js";
import { v4 as uuidv4 } from "uuid";
import useCommonHelper from "@/use/useCommonHelper";
const { useTruncate, removeBodyScroll } = useCommonHelper();

const persona = ref("");
const performanceData = ref([]);
const scriptItems = ref([]);
const headers = ref([]);
const scripts = ref([]);
const hideOverlay = false;
const data = ref([]);
const summaryDetails = ref([]);
const networkDialog = ref(false);
const uuid = ref("");
const networkData = ref([]);
const networkDialogTitle = ref("");
const chartOptions = ref({});

const networkHeaders = ref([
  { title: "Name", key: "name", width: "40%", sortable: false },
  { title: "Status", key: "status", width: "20%", sortable: false },
  { title: "Type", key: "type", width: "20%", sortable: false },
  { title: "Time", key: "time", width: "20%", sortable: false },
]);

const props = defineProps(["tabObject"]);
const performanceHelper = usePerformanceHelper();

watch(
  () => props.tabObject,
  (newVal) => {
    if (newVal.componentName === "PerformanceTab") {
      performanceData.value = newVal.data.qumDataList;
      persona.value = newVal.data.persona;
      initialiseUI();
    }
  }
);

watch(networkDialog, (val) => {
  removeBodyScroll(val);
});

onMounted(() => {
  setUUID();
  performanceData.value = props.tabObject.data.qumDataList;
  persona.value = props.tabObject.data.persona;
  initialiseUI();
});

const setUUID = () => {
  uuid.value = uuidv4();
};

const initialiseUI = () => {
  if (performanceData.value) {
    const scriptsTemp = performanceData.value;
    scripts.value = scriptsTemp.map((scr) => {
      return {
        id: uuid.value,
        name: scr.scriptName,
        scenariosCount: scr.scenarios.length,
        scenarios: scr.scenarios.map((scn) => {
          return {
            id: uuid.value,
            name: scn.scenarioName,
            activitiesCount: scn.activities.length,
            activities: scn.activities.map((act) => {
              return {
                id: uuid.value,
                name: act.activityName,
                messagesCount: act.actionCount,
                ...act,
                actionMessagesList: act.actionMessagesList.map((msg) => {
                  return {
                    id: uuid.value,
                    ...msg,
                  };
                }),
              };
            }),
          };
        }),
      };
    });
  } else {
    // $router.push({ name: "upload" });
  }

  headers.value = [
    { title: "Tasks", key: "scenario", width: "15%", sortable: false },
    {
      title: "Scenarios",
      key: "task",
      width: "20%",
      sortable: false,
    },
    { title: "Steps", key: "step", width: "15%", sortable: false },
    { title: "Actions", key: "action", width: "25%", sortable: false },
    {
      title: "User Action Count",
      key: "actualAction",
      width: "15%",
      sortable: false,
    },
    { title: "Validity", key: "validity", width: "15%", sortable: false },
    { title: "Outcome", key: "outcome", width: "15%", sortable: false },
    {
      title: "User Action Time",
      key: "userActionTime",
      width: "15%",
      sortable: false,
    },
    {
      title: "System Delay",
      key: "systemDelay",
      width: "15%",
      sortable: false,
    },
    { title: "Total Time", key: "totalTime", width: "15%", sortable: false },
    {
      title: "Network Calls",
      key: "networkCalls",
      width: "15%",
      sortable: false,
    },
    // { title: "Broken Resources", key: "brokenResources", width: "15%", sortable: false },
  ];

  createTableData();
  createSummary();
};

const createSummary = () => {
  let tasks = 0,
    steps = 0,
    actions = 0;
  scripts.value.forEach((script) => {
    tasks += script.scenarios.length;
    script.scenarios.forEach((scenario) => {
      steps += scenario.activities.length;
      scenario.activities.forEach((activity) => {
        actions += activity.actionMessagesList.length;
      });
    });
  });

  let userActionTime = 0,
    systemDelay = 0,
    totalTime = 0,
    networkCalls = 0;

  scripts.value.forEach((scr) => {
    scr.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.actionMessagesList.forEach((item) => {
          userActionTime = userActionTime + item.userActionTime;
          systemDelay = systemDelay + item.systemDelay;
          totalTime = parseFloat(userActionTime) + parseFloat(systemDelay);
          networkCalls = networkCalls + item.networkEntries.length;
        });
      });
    });
  });

  data.value = [
    {
      name: "Name",
      value: window.info[0].applicationName,
    },
    {
      name: "Persona",
      value: persona,
    },
    {
      name: "Tasks",
      value: scripts.value.length,
    },
    {
      name: "Scenarios",
      value: tasks,
    },
    {
      name: "Steps",
      value: steps,
    },
    {
      name: "Actions",
      value: actions,
    },
    {
      name: "Network Calls",
      value: networkCalls,
    },
  ];

  summaryDetails.value = [
    {
      name: "User Action Time",
      y: millisecondsToStr(userActionTime),
      color: "#ffe188",
    },
    {
      name: "System Delay",
      y: millisecondsToStr(systemDelay),
      color: "#88d567",
    },
  ];

  createPieChart();
};

const createPieChart = () => {
  chartOptions.value = {
    ...chartConfig,
    series: [
      {
        name: "Secs",
        colorByPoint: true,
        data: summaryDetails.value,
      },
    ],
  };
};

const createTableData = () => {
  scriptItems.value = [];
  scripts.value.forEach((scr) => {
    const script = performanceHelper.getScriptObj(scr);
    scriptItems.value.push(script);

    scr.scenarios.forEach((scn) => {
      const scenario = performanceHelper.getScenarioObj(scn);
      scriptItems.value.push(scenario);

      scn.activities.forEach((act) => {
        const activity = performanceHelper.getActivityObj(act);
        scriptItems.value.push(activity);

        act.actionMessagesList.forEach(async (msg) => {
          const item = performanceHelper.getMessageObj(msg);
          scriptItems.value.push(item);
        });
      });
    });
  });
};

const showNetworkDetails = (item) => {
  networkDialog.value = true;
  networkDialogTitle.value = "Network Details";
  networkData.value = item.networkDetails.map((x) => {
    return {
      name: x.name,
      status: x.responseStatus,
      type: x.initiatorType,
      time: `${x.duration.toString().split(".")[0]} ms`,
    };
  });
};

const millisecondsToStr = (milliseconds) => {
  let temp = parseFloat((milliseconds / 1000).toFixed(2));
  return temp;
};
</script>

