import { ref } from 'vue';

export default function useMetricsHelper() {
    function useSumOfTasks(scr) {
        const sum = ref(0);
        scr.scenarios.forEach((scn) => {
            sum.value += scn.activities.length;
        });
        return sum.value;
    }
    
    function useSumOfActions(scr, type) {
        const sum = ref(0);
        scr.scenarios.forEach((scn) => {
            scn.activities.forEach((act) => {
                if(type === 'designHygiene') {
                    sum.value += act.designHygieneList.length;
                } else if(type === 'i18N') {
                    sum.value += act.i18NDataList.length;
                } else if(type === 'accessibility') {
                    sum.value += act.accessibilityData.length;
                } else if(type === 'accessibilityMobile') {
                    sum.value += act.accessibilityData.length;
                } else if(type === 'accessibilityAndroid') {
                    sum.value += act.accessibilityData.length;
                } else if(type === 'vulnerability') {
                    sum.value += act.vulnerability.length;
                } else {
                    sum.value += act.actionMessagesList.length;
                }
            });
        });
        return sum.value;
    }

    function useSumOfActionsForScenario(scn, type) {
        let sum = ref(0);
        scn.activities.forEach((act) => {
            if(type === 'designHygiene') {
                sum.value = sum.value + act.designHygieneList.length;
            } else if(type === 'i18N') {
                sum.value = sum.value + act.i18NDataList.length;
            } else if(type === 'accessibility') {
                sum.value = sum.value + act.accessibilityData.length;
            } else if(type === 'accessibilityMobile') {
                sum.value = sum.value + act.accessibilityData.length;
            } else if(type === 'accessibilityAndroid') {
                sum.value += act.accessibilityData.length;
            } else if(type === 'vulnerability') {
                sum.value += act.vulnerability.length;
            } else {
                sum.value = sum.value + act.actionMessagesList.length;
            }
        });
        return sum.value;
    }

    return {
        useSumOfTasks,
        useSumOfActions,
        useSumOfActionsForScenario
    }
}