onMounted(() => {
  const groupBySprintPathDetails = window.qumReportSummaryPathDetails.reduce(
    (acc, curr) => {
      const foundIndex = acc.findIndex((item) => item.sprint === curr.sprint);

      foundIndex !== -1
        ? acc[foundIndex].sprintData.push({ ...curr }) // Update existing sprint
        : acc.push({ sprint: curr.sprint, sprintData: [{ ...curr }] }); // Add a new sprint

      return acc;
    },
    []
  );

  groupBySprintPathDetails.sort(
    (a, b) => parseFloat(a.sprint) - parseFloat(b.sprint)
  );
  sprintWisePathDetails = groupBySprintPathDetails;

  sprintList = groupBySprintPathDetails.map((ele) => ele.sprint);
  sprintSelected.value = sprintList[0];
  changeSprint();
  if (!showExecutionDropdown.value) {
    loadData();
  }

  const flag = localStorage.getItem("ChartType");
  const localStorageSprint = localStorage.getItem("selectedSprint");

  if (flag != null && flag != undefined && localStorageSprint) {
    localStorage.removeItem("ChartType");
    localStorage.removeItem("selectedSprint");

    showExecutionDropdown.value = true;

    sprintSelected.value = localStorageSprint;
    changeSprint();

    labelToChangeCheckboxText.value = `Click here to see consolidated data for ${sprintSelected.value}`;
    setTimeout(() => {
      scrollToMetrics(flag);
    }, 200);
  }

  const hidePersonaVal = !!(
    window.info &&
    window.info[0] &&
    window.info[0].hidePersona
  );
  // showExecutionDropdown.value = (window.info && window.info[0] && window.info[0].hidePersona) || false;
  // showSprintAndExecutionDropdown.value = (window.info && window.info[0] && !window.info[0].hidePersona) || true;

  showExecutionDropdown.value = hidePersonaVal;
  showSprintAndExecutionDropdown.value = !hidePersonaVal;

  if (window.info && window.info[0] && window.info[0].hidePersona) {
    changeSprint();
    changePersonaView();
  }

  if (
    window.info &&
    window.info[0] &&
    !window.info[0].hidePersona &&
    sprintList.length === 1 &&
    sprintWisePathDetails[0].sprintData.length === 1
  ) {
    showExecutionDropdown.value = true;
    changePersonaView();
  }
});

