const scrollToMetrics = (flag) => {
  if (
    document.querySelector("." + flag) != null &&
    document.querySelector("." + flag) != undefined
  ) {
    switch (flag) {
      case "features":
        document
          .querySelector("." + flag)
          .parentElement.parentElement.scrollIntoView({ behavior: "smooth" });
        break;
      case "qumPerformance":
