  } else {
    const trendChartData = window.trendsChartSummary;

    const groupBySprintData = trendChartData.reduce((acc, curr) => {
      const foundIndex = acc.findIndex((item) => item.sprint === curr.sprint);
      if (foundIndex !== -1) {
        // Update existing sprint
        acc[foundIndex].sprintData.push({ ...curr });
      } else {
        // Add a new sprint
        acc.push({ sprint: curr.sprint, sprintData: [{ ...curr }] });
      }
      return acc;
    }, []);

    selectedSprintData = groupBySprintData.find(
      (ele) => ele.sprint === sprintSelected.value
    );

    // get personas for selected sprint data
    selectedSprintData.sprintData.forEach((version) => {
      version.data.forEach((category) => {
        category.data.forEach((personaObj) => {
          if (!personas.includes(personaObj.persona)) {
            personas.push(personaObj.persona);
          }
        });
      });
    });

    selectedSprintMetrics = [];
    selectedSprintData.sprintData.forEach((version) => {
      version.data.forEach((category) => {
        const foundIndex = selectedSprintMetrics.findIndex(
          (e) => e === category.category
        );
        if (foundIndex === -1) {
          selectedSprintMetrics.push(category.category);
        }
      });
    });
  }

  personas.forEach((item) => {
    personaItems.value.push({
      name: item,
      disabled: true,
    });
  });

  if (personas.length > 1) {
    isCompare.value = false;
    disableSeeDetails.value = true;

    personaItems.value.unshift({
      name: "All Personas",
      disabled: false,
    });

    selectedPersonas = [personaItems.value[0]];
    hint.value = true;

    if (showExecutionDropdown.value) {
      createConsolidatedPersonasSummary();
    } else {
      createConsolidatedExecutionSummary();
    }
  } else {
    isCompare.value = false;
    const name = personas[0];
    // this.resetData();
    personaItems.value[0].disabled = true;
    selectedPersonas = [personaItems.value[0]];

    if (showExecutionDropdown.value) {
      disableSeeDetails.value = false;
      setDefaultPersona(name);
    } else {
      disableSeeDetails.value = true;
      createConsolidatedExecutionSummary();
    }
  }
};

const changeSprint = () => {
  const selectedSprintObj = sprintWisePathDetails.find(
    (ele) => ele.sprint === sprintSelected.value
  );
  executionItems = selectedSprintObj.sprintData.map((item) => {
    const d = new Date(item.reportTime);

    const datestring =
      ("0" + d.getHours()).slice(-2) +
      ":" +
      ("0" + d.getMinutes()).slice(-2) +
      " " +
      ("0" + d.getDate()).slice(-2) +
      "-" +
      ("0" + (d.getMonth() + 1)).slice(-2) +
      "-" +
      d.getFullYear();

    return {
      ...item,
      reportTime: datestring,
    };
  });

  if (showExecutionDropdown.value) {
    const localStorageExecution = localStorage.getItem("selectedExecution");
    if (localStorageExecution) {
      localStorage.removeItem("selectedExecution");
      selectedExecution = executionItems.find(
        (e) => e.reportTime === localStorageExecution
      );
    } else {
      selectedExecution = executionItems[0];
    }
    changeExecution();
    labelToChangeCheckboxText.value = `Click here to see consolidated data for ${sprintSelected.value}`;
  } else {
    loadData();
  }
};

const changeExecution = () => {
  const { version } = selectedExecution;
  loadScripts(version);
};

const changePersona = (value) => {
  const allPersonaIndex = value.findIndex((e) => e.name === "All Personas");

  if (allPersonaIndex !== -1) {
    isCompare.value = false;
    // this.hint = "Select two or more personas to start comparing";
    hint.value = true;
    selectedPersonas.splice(0, allPersonaIndex); // Remove elements before 'all'
    selectedPersonas.splice(allPersonaIndex + 1); // Remove elements after 'all'

    personaItems.value.forEach((persona) => {
      if (persona.name !== "All Personas") {
        persona.disabled = true;
      }
    });
    disableSeeDetails.value = true;

    if (showExecutionDropdown.value) {
      createConsolidatedPersonasSummary();
    } else {
      createConsolidatedExecutionSummary();
    }
  } else {
    if (selectedPersonas.length === 1) {
      isCompare.value = false;
      // this.hint = "Select two or more personas to start comparing";
      hint.value = true;
      const selected = selectedPersonas[0].name;
      const obj = personaItems.value.find((x) => x.name === selected);
      const index = personaItems.value.indexOf(obj);
      personaItems.value[index].disabled = true;
      const { name } = value[0];

      if (showExecutionDropdown.value) {
        disableSeeDetails.value = false;
        setDefaultPersona(name);
      } else {
        disableSeeDetails.value = true;
        createConsolidatedExecutionSummary();
      }
    } else {
      hint.value = false;
      isCompare.value = true;
      disableSeeDetails.value = false;

      personaItems.value.forEach((item) => (item.disabled = false));

      if (value.length === 0) {
        selectedPersonas = personaItems.value.filter(
          (e) => e.name !== "All Personas"
        );
      }

      createHeaders();
      if (showExecutionDropdown.value) {
        createPersonaRows();
      } else {
        createConsolidatedExecutionSummary();
      }
    }
  }
};

const createConsolidatedExecutionSummary = () => {
  resetData();
