    const personaName = personaEle.name;
    if (personaName !== "All Personas") {
      cardsData[personaName] = {};

      selectedSprintMetrics.forEach((metric) => {
        if (metric !== "i18N") {
          const metricElementsArr = metricDataKeys[metric].reduce(
            (acc, key) => {
              acc[key] = [];
              return acc;
            },
            {}
          );

          let noCategoryFound = 0;
          let noPersonaFound = 0;
          selectedSprintData.sprintData.forEach((sprintVersion) => {
            const category = sprintVersion.data.find(
              (o) => o.category === metric
            );
            if (category) {
              let persona = category.data.find(
                (o) => o.persona === personaName
              );

              if (persona) {
                let data = persona.personaData;
                if (metric === "designHygiene") {
                  data = {
                    tasks: persona.personaData.tasks,
                    fonts: persona.personaData.typography.fontFamily,
                    colors: persona.personaData.colors.color,
                    backgroundColors:
                      persona.personaData.colors["background-color"],
                  };
                }
                Object.keys(data).forEach((label) => {
                  const dataValue =
                    typeof data[label] === "string" ? Number(data[label]) : 0;
                  if (metricElementsArr[label]) {
                    metricElementsArr[label].push(dataValue);
                  }
                });
              } else {
                noPersonaFound++;
                metricDataKeys[metric].forEach((item) => {
                  if (metricElementsArr[item]) {
                    metricElementsArr[item].push(0);
                  }
                });
              }
            } else {
              noCategoryFound++;
              metricDataKeys[metric].forEach((item) => {
                if (metricElementsArr[item]) {
                  metricElementsArr[item].push(0);
                }
              });
            }
          });

          if (
            selectedSprintData.sprintData.length !==
            noCategoryFound + noPersonaFound
          ) {
            cardsData[personaName][metric] = metricElementsArr;
          }
        } else {
          metricDataKeys[metric] = [];

          let noCategoryFound = 0;
          let noPersonaFound = 0;

          selectedSprintData.sprintData.map((version) => {
            const i18NObj = version.data.find((ele) => ele.category === metric);

            const selectedPersNames = selectedPersonas.map((e) => e.name);

            if (i18NObj) {
              i18NObj.data.forEach((persona) => {
                if (
                  selectedPersNames.includes(persona.persona) ||
                  selectedPersNames.includes("All Personas")
                ) {
                  persona.personaData.violations.forEach((violation) => {
                    if (!metricDataKeys[metric].includes(violation.language)) {
                      metricDataKeys[metric].push(violation.language);
                    }
                  });
                }
              });
            }
          });

          const metricElementsArr = metricDataKeys[metric].reduce(
            (acc, key) => {
              acc[key] = [];
              return acc;
            },
            {}
          );
          metricElementsArr.tasks = [];
          // metricElementsArr.languages = metricDataKeys[metric];
          metricElementsArr.languages = [];

          selectedSprintData.sprintData.forEach((sprintVersion) => {
            const category = sprintVersion.data.find(
              (o) => o.category === metric
            );
            if (category) {
              let persona = category.data.find(
                (o) => o.persona === personaName
              );

              if (persona) {
                const { tasks, violations } = persona.personaData;
                metricElementsArr.tasks.push(Number(tasks));

                violations.forEach((violation) => {
                  if (
                    !metricElementsArr.languages.includes(violation.language)
                  ) {
                    metricElementsArr.languages.push(violation.language);
                  }

                  if (metricElementsArr[violation.language]) {
                    let sum = 0;
                    Object.keys(violation).forEach((key) => {
                      if (key !== "language") {
                        sum += Number(violation[key]);
                      }
                    });

                    metricDataKeys[metric].forEach((item) => {
                      if (item === violation.language) {
                        metricElementsArr[violation.language].push(
                          Math.round(sum / tasks)
                        );
                      } else {
                        metricElementsArr[item].push(0);
                      }
                    });
                  }
