          Math.round(accessData.wcagACount / tasks) +
          Math.round(accessData.wcagAACount / tasks) +
          Math.round(accessData.wcagAAACount / tasks);
        comparePersonas.value.accessibilityIOS.items[4][personaName] =
          Math.round(accessData.miscellaneousCount / tasks);
        comparePersonas.value.accessibilityIOS.items[5][personaName] =
          wcagHelper.useConformanceLevel(
            accessData.wcagACount,
            accessData.wcagAACount,
            accessData.wcagAAACount
          );
      } else {
        emptyAccessIOS++;
        comparePersonas.value.accessibilityIOS.items.forEach((_, i) => {
          comparePersonas.value.accessibilityIOS.items[i][personaName] = "-";
        });
      }

      if (averagedCardsData[personaName].browserPerformance) {
        const browserData = averagedCardsData[personaName].browserPerformance;
        const tasks = browserData.tasks;
        comparePersonas.value.browserPerformance.items[0][personaName] = tasks;
        comparePersonas.value.browserPerformance.items[1][personaName] =
          useMillisecondsToStr(browserData.pageCompletionTime / tasks);
        comparePersonas.value.browserPerformance.items[2][personaName] =
          useMillisecondsToStr(browserData.networkLatency / tasks);
        comparePersonas.value.browserPerformance.items[3][personaName] =
          useMillisecondsToStr(browserData.contentDownLoad / tasks);
      } else {
        emptyBrowserPerf++;
        comparePersonas.value.browserPerformance.items.forEach((_, i) => {
          comparePersonas.value.browserPerformance.items[i][personaName] = "-";
        });
      }

      if (averagedCardsData[personaName].designHygiene) {
