          desHygData.colors / tasks
        );
        comparePersonas.value.designHygiene.items[3][personaName] = Math.round(
          desHygData.backgroundColors / tasks
        );
      } else {
        emptyDesHygn++;
        comparePersonas.value.designHygiene.items.forEach((_, i) => {
          comparePersonas.value.designHygiene.items[i][personaName] = "-";
        });
      }

      if (averagedCardsData[personaName].qumPerformance) {
        const qumPerfData = averagedCardsData[personaName].qumPerformance;
        const tasks = qumPerfData.tasks;
        comparePersonas.value.qumPerformance.items[0][personaName] = tasks;
        comparePersonas.value.qumPerformance.items[1][personaName] =
          useMillisecondsToStr(qumPerfData.userActionTime / tasks);
        comparePersonas.value.qumPerformance.items[2][personaName] =
          useMillisecondsToStr(qumPerfData.systemDelay / tasks);
        comparePersonas.value.qumPerformance.items[3][personaName] = Math.round(
          qumPerfData.networkCalls / tasks
        );
      } else {
        emptyQumPerf++;
        comparePersonas.value.qumPerformance.items.forEach((_, i) => {
          comparePersonas.value.qumPerformance.items[i][personaName] = "-";
        });
      }

      if (averagedCardsData[personaName].i18N) {
        const i18NData = averagedCardsData[personaName].i18N;

        const languages = [];
        i18NData.languages.forEach((e) => {
          if (!Array.isArray(i18NData[e])) {
            languages.push(e);
          }
        });

        const tasks = i18NData.tasks;
        const avgViolations = languages.map((e) => {
          return {
            language: e,
            // violations: Number.isInteger(i18NData[e]) ? Number(i18NData[e]) : (i18NData[e]).toFixed(2),
            violations: Math.round(i18NData[e]),
          };
        });

        comparePersonas.value.i18N.items[0][personaName] = tasks;
        comparePersonas.value.i18N.items[1][personaName] = languages.join(",");

        for (
          let index = 2;
          index < comparePersonas.value.i18N.items.length;
          index++
        ) {
          if (avgViolations[index - 2]) {
            const elIndex = comparePersonas.value.i18N.items.findIndex((el) =>
              el.name.includes(avgViolations[index - 2].language)
            );
            comparePersonas.value.i18N.items[elIndex][personaName] =
              avgViolations[index - 2].violations;
            if (
              !comparePersonas.value.i18N.items[index][personaName] ||
              comparePersonas.value.i18N.items[index][personaName] === ""
            ) {
              comparePersonas.value.i18N.items[index][personaName] = "-";
            }
          } else {
            if (
              !comparePersonas.value.i18N.items[index][personaName] ||
              comparePersonas.value.i18N.items[index][personaName] === ""
            ) {
              comparePersonas.value.i18N.items[index][personaName] = "-";
            }
          }
        }
      } else {
        emptyI18N++;
        comparePersonas.value.i18N.items.forEach((_, i) => {
          comparePersonas.value.i18N.items[i][personaName] = "-";
        });
        const obj = comparePersonas.value.i18N.headers.find(
          (x) => x.text === personaName
        );
        const index = comparePersonas.value.i18N.headers.indexOf(obj);
        comparePersonas.value.i18N.headers[index].disabled = true;
      }
    });

    // To hide the table if all persona values are empty
    if (emptyFeatures === selectedPersonas.length) {
      comparePersonas.value.features.items = [];
    }
    if (emptyAccess === selectedPersonas.length) {
      comparePersonas.value.accessibility.items = [];
    }
    if (emptyAccessMobile === selectedPersonas.length) {
      comparePersonas.value.accessibilityMobile.items = [];
    }
    if (emptyAccessAndroid === selectedPersonas.length) {
      comparePersonas.value.accessibilityAndroid.items = [];
    }
    if (emptyAccessIOS === selectedPersonas.length) {
      comparePersonas.value.accessibilityIOS.items = [];
    }
    if (emptyBrowserPerf === selectedPersonas.length) {
      comparePersonas.value.browserPerformance.items = [];
    }
    if (emptyQumPerf === selectedPersonas.length) {
      comparePersonas.value.qumPerformance.items = [];
    }
    if (emptyI18N === selectedPersonas.length) {
      comparePersonas.value.i18N.items = [];
    }
    if (emptyDesHygn === selectedPersonas.length) {
      comparePersonas.value.designHygiene.items = [];
    }
  }
};

const calculateArrayAverages = (obj) => {
  const result = {};
  // Iterate over the outer keys ("MarketingAgent", "Journalist")
  for (const outerKey in obj) {
    const outerObj = obj[outerKey];
    result[outerKey] = {};
    // Iterate over the inner keys ("accessibility", "qumPerformance", "browserPerformance", "features")
    for (const innerKey in outerObj) {
      result[outerKey][innerKey] = {};
      // Iterate over the arrays in the inner object
      for (const arrayKey in outerObj[innerKey]) {
        const array = outerObj[innerKey][arrayKey];
        // Calculate the average of the array
        // const average = array.reduce((sum, value) => sum + value, 0) / array.length;
        const sum = array.reduce((sum, value) => sum + value, 0);
        if (typeof sum === "number") {
          // Store the average in the result object
          result[outerKey][innerKey][arrayKey] = sum / array.length;
        } else {
          result[outerKey][innerKey][arrayKey] = array;
        }
      }
    }
  }
  return result;
};

const calculateAllPersonasForAllExecutions = (obj) => {
  const result = {};
  for (const key in obj) {
    for (const innerKey in obj[key]) {
      if (!result[innerKey]) {
        result[innerKey] = {};
      }
      for (const prop in obj[key][innerKey]) {
        if (Array.isArray(obj[key][innerKey][prop])) {
          if (!result[innerKey][prop]) {
            result[innerKey][prop] = [];
          }
          if (obj[key][innerKey][prop].length) {
            result[innerKey][prop].push(...obj[key][innerKey][prop]);
          }
        } else {
          if (!result[innerKey][prop]) {
            result[innerKey][prop] = 0;
          }
          result[innerKey][prop] += Number(obj[key][innerKey][prop]);
        }
      }
    }
  }
  return result;
};

