      languagesSupported: [...new Set(sumOfData.languagesSupported)],
      avgViolations: averageVoilations,
    };
  }

  if (window["vulnerability"]) {
    summaryCards.vulnerability.show = true;
    const vulnerabilityData = window.vulnerability.map((persona) => ({
      tasks: summaryHelper.getSumOfScenarios(persona.qumDataList),
      high: summaryHelper.getSecurityIssuesAsPerCategory(
        persona.qumDataList,
        "High"
      ),
      medium: summaryHelper.getSecurityIssuesAsPerCategory(
        persona.qumDataList,
        "Medium"
      ),
      low: summaryHelper.getSecurityIssuesAsPerCategory(
        persona.qumDataList,
        "Low"
      ),
      informational: summaryHelper.getSecurityIssuesAsPerCategory(
        persona.qumDataList,
        "Informational"
      ),
      falsePositive: summaryHelper.getSecurityIssuesAsPerCategory(
        persona.qumDataList,
        "False Positive"
      ),
    }));

    const sumOfData = vulnerabilityData.reduce(
      (acc, curr) => ({
        tasks: acc.tasks + curr.tasks,
        high: parseFloat(acc.high) + parseFloat(curr.high),
        medium: parseFloat(acc.medium) + parseFloat(curr.medium),
        low: parseFloat(acc.low) + parseFloat(curr.low),
        informational:
          parseFloat(acc.informational) + parseFloat(curr.informational),
        falsePositive:
          parseFloat(acc.falsePositive) + parseFloat(curr.falsePositive),
      }),
      {
        tasks: 0,
        high: 0,
        medium: 0,
        low: 0,
        informational: 0,
        falsePositive: 0,
      }
    );
    summaryCards.vulnerability.data = {
      tasks: sumOfData.tasks,
      high: Math.round(sumOfData.high / sumOfData.tasks),
      medium: Math.round(sumOfData.medium / sumOfData.tasks),
      low: Math.round(sumOfData.low / sumOfData.tasks),
      informational: Math.round(sumOfData.informational / sumOfData.tasks),
      falsePositive: Math.round(sumOfData.falsePositive / sumOfData.tasks),
    };
  }
};

