const createAccTable = (persona, personaObject) => {
  if (personaObject.accessibility) {
    const accessibilityData = summaryHelper.getMetricDataList(
      personaObject,
      "accessibility"
    );
    const tasks = summaryHelper.getSumOfScenarios(accessibilityData);
    const accessibilityTableData = {
      tasks: tasks,
      wcagACount: summaryHelper.getAvgNoOfViolations(
        accessibilityData,
        "wcag2a",
        tasks
      ),
      wcagAACount: summaryHelper.getAvgNoOfViolations(
        accessibilityData,
        "wcag2aa",
        tasks
      ),
      wcagAAACount: summaryHelper.getAvgNoOfViolations(
        accessibilityData,
        "wcag2aaa",
        tasks
      ),
      miscellaneousCount: summaryHelper.getAvgNoOfViolations(
        accessibilityData,
        "miscellaneous",
        tasks
      ),
    };

    comparePersonas.value.accessibility.items[0][persona] = tasks;
    comparePersonas.value.accessibility.items[1][persona] = Math.round(
      accessibilityTableData.wcagACount
    );
    comparePersonas.value.accessibility.items[2][persona] =
      Math.round(accessibilityTableData.wcagACount) +
      Math.round(accessibilityTableData.wcagAACount);
    comparePersonas.value.accessibility.items[3][persona] =
      Math.round(accessibilityTableData.wcagACount) +
      Math.round(accessibilityTableData.wcagAACount) +
      Math.round(accessibilityTableData.wcagAAACount);
    comparePersonas.value.accessibility.items[4][persona] = Math.round(
      accessibilityTableData.miscellaneousCount
    );
    comparePersonas.value.accessibility.items[5][persona] =
      wcagHelper.useConformanceLevel(
        Math.round(accessibilityTableData.wcagACount),
        Math.round(accessibilityTableData.wcagAACount),
        Math.round(accessibilityTableData.wcagAAACount)
      );
  } else {
    comparePersonas.value.accessibility.items[0][persona] = "-";
    comparePersonas.value.accessibility.items[1][persona] = "-";
    comparePersonas.value.accessibility.items[2][persona] = "-";
    comparePersonas.value.accessibility.items[3][persona] = "-";
    comparePersonas.value.accessibility.items[4][persona] = "-";
    comparePersonas.value.accessibility.items[5][persona] = "-";
    const obj = comparePersonas.value.accessibility.headers.find(
      (x) => x.text === persona
    );
    const index = comparePersonas.value.accessibility.headers.indexOf(obj);
    comparePersonas.value.accessibility.headers[index].disabled = true;
  }
};

