const createI18NTable = (persona, personaObject) => {
  if (personaObject.i18N) {
    const i18nData = summaryHelper.getMetricDataList(personaObject, "i18N");
    const sumOfScnearios = summaryHelper.getSumOfScenarios(i18nData);

    const languages = [...new Set(i18nData.map((item) => item.language))];
    const avgViolations = summaryHelper.getAvgViolations(i18nData);

    const i18NReportTableData = {
      tasks: sumOfScnearios,
      languagesSupported: languages,
      avgViolations,
    };
    comparePersonas.value.i18N.items[0][persona] = i18NReportTableData.tasks;
    comparePersonas.value.i18N.items[1][persona] =
      i18NReportTableData.languagesSupported.join(",");

    for (
      let index = 2;
      index < comparePersonas.value.i18N.items.length;
      index++
    ) {
      if (avgViolations[index - 2]) {
        const elIndex = comparePersonas.value.i18N.items.findIndex((el) =>
          el.name.includes(avgViolations[index - 2].language)
        );
        comparePersonas.value.i18N.items[elIndex][persona] =
          avgViolations[index - 2].violations;
        if (
          !comparePersonas.value.i18N.items[index][persona] ||
          comparePersonas.value.i18N.items[index][persona] === ""
        ) {
          comparePersonas.value.i18N.items[index][persona] = "-";
        }
      } else {
        if (
          !comparePersonas.value.i18N.items[index][persona] ||
          comparePersonas.value.i18N.items[index][persona] === ""
        ) {
          comparePersonas.value.i18N.items[index][persona] = "-";
        }
      }
    }
  } else {
    comparePersonas.value.i18N.items.forEach((_, i) => {
      comparePersonas.value.i18N.items[i][persona] = "-";
    });
    const obj = comparePersonas.value.i18N.headers.find(
      (x) => x.text === persona
    );
    const index = comparePersonas.value.i18N.headers.indexOf(obj);
    comparePersonas.value.i18N.headers[index].disabled = true;
  }
};

