const getUniqueLanguages = () => {
  i18NLanguages = []; // clear the existing languages first

  selectedPersonas.forEach((item) => {
    if (item.name === "All Personas") return;

    const persona = item.name;
    const personaObject = window[persona];
    if (personaObject.i18N) {
      const i18nData = summaryHelper.getMetricDataList(personaObject, "i18N");
      const languages = i18nData.map((item) => item.language);
      i18NLanguages = [...languages, ...i18NLanguages];
    }
  });
  return [...new Set(i18NLanguages)];
};

const loadScripts = (version) => {
  window["features"] = undefined;
  window["qumPerformance"] = undefined;
  window["i18N"] = undefined;
  window["accessibility"] = undefined;
  window["accessibilityMobile"] = undefined;
  window["accessibilityAndroid"] = undefined;
  window["accessibilityIOS"] = undefined;
  window["browserPerformance"] = undefined;
  window["designHygiene"] = undefined;
  window["vulnerability"] = undefined;

  const names = [
    "info",
    "header",
    "accessibility",
    "accessibilityMobile",
    "accessibilityAndroid",
    "accessibilityIOS",
    "browserPerformance",
    "features",
    "i18N",
    "qumPerformance",
    "designHygiene",
    "vulnerability",
  ];

  let allFilesLoaded = 0;

  names.forEach((name) => {
    let script = document.createElement("script");
    script.type = "text/javascript";
    script.addEventListener("load", () => {
      allFilesLoaded++;
      if (window.info) {
        personas = window.info[0].persona.split(",");
        personas.forEach((item) => {
          window[item] = {};
        });
      }
      if (window.accessibility) {
        assignPersona(window.accessibility, "accessibility");
      }
      if (window.accessibilityMobile) {
        assignPersona(window.accessibilityMobile, "accessibilityMobile");
      }
      if (window.accessibilityAndroid) {
        assignPersona(window.accessibilityAndroid, "accessibilityAndroid");
      }
      if (window.accessibilityIOS) {
        assignPersona(window.accessibilityIOS, "accessibilityIOS");
      }
      if (window.browserPerformance) {
        assignPersona(window.browserPerformance, "browserPerformance");
      }
      if (window.features) {
        assignPersona(window.features, "features");
      }
      if (window.i18N) {
        assignPersona(window.i18N, "i18N");
      }
      if (window.qumPerformance) {
        assignPersona(window.qumPerformance, "qumPerformance");
      }
      if (window.designHygiene) {
        assignPersona(window.designHygiene, "designHygiene");
      }

      if (window.vulnerability) {
        assignPersona(window.vulnerability, "vulnerability");
      }

      if (names.length === allFilesLoaded) {
        loadData();
      }
      if (window.info) {
        window["executionTime"] = version;
      }
    });

    script.addEventListener("error", () => {
      // if (self.$router.history.current.path !== "/upload") {
      //   self.$router.push({ name: "upload" });
      // }
      allFilesLoaded++;

      if (names.length === allFilesLoaded) {
        loadData();
      }
    });
    script.src = `${process.env.FILE_PATH}${version}/quantitative-user-metrics/execution/${name}.js`;
    document.head.appendChild(script);
  });
};

