<template>
  <v-app id="app">
    <HeaderComponent :headerData="headerData" :headerTitle="headerTitle" />
    <v-main>
      <v-container fluid>
        <v-progress-circular
          indeterminate
          v-if="!isLoaded"
        ></v-progress-circular>
        <RouterView v-else :headerTitle="headerTitle" />
      </v-container>
    </v-main>
    <FooterComponent :footerData="headerData" />
  </v-app>
</template>

<script setup>
import { ref, onMounted } from "vue";
import HeaderComponent from "./components/HeaderComponent/HeaderComponent";
import FooterComponent from "./components/FooterComponent/FooterComponent.vue";
import HighchartsVue from "highcharts-vue";
const isLoaded = ref(false);
const personas = ref([]);
const headerData = ref({});
const headerTitle = ref("");
onMounted(() => {
  loadSummaryPathDetails();
  loadTrendSummary();
  setTimeout(() => {
    loadScripts();
  }, 1000);
});

const loadTrendSummary = () => {
  let script = document.createElement("script");
  script.type = "text/javascript";
  script.addEventListener("load", () => {
    const result = window.trendsChartSummary.find(
      (o) => o.type === "trendsData"
    );
    if (result) {
      window.trendsChartSummary = result.data;
    }
  });
  script.addEventListener("error", () => {});
  script.src = `${process.env.FILE_PATH}trendsChartSummary.js`;
  document.head.appendChild(script);
};

const loadSummaryPathDetails = () => {
  let script = document.createElement("script");
  script.type = "text/javascript";
  script.addEventListener("load", () => {
    window.qumReportSummaryPathDetails.sort((a, b) => {
      return new Date(b.reportTime) - new Date(a.reportTime);
    });
  });
  script.addEventListener("error", () => {});
  script.src = `${process.env.FILE_PATH}qumReportSummaryPathDetails.js`;
  document.head.appendChild(script);
};

const loadScripts = () => {
  const names = [
    "info",
    "header",
    "accessibility",
    "accessibilityMobile",
    "accessibilityAndroid",
    "accessibilityIOS",
    "browserPerformance",
    "features",
    "i18N",
    "qumPerformance",
    "designHygiene",
    "vulnerability",
  ];
  names.forEach((name) => {
    let script = document.createElement("script");
    script.type = "text/javascript";
    script.addEventListener("load", () => {
      if (window.info.length) {
        personas.value = window.info[0].persona.split(",");
        personas.value.forEach((item) => {
          window[item] = {};
        });
        headerTitle.value = window.info[0].reportHeading;
      }
      if (window.header) {
        headerData.value = window.header;
      }
      if (window.accessibility) {
        assignPersona(window.accessibility, "accessibility");
      }

      if (window.accessibilityMobile) {
        assignPersona(window.accessibilityMobile, "accessibilityMobile");
      }

      if (window.browserPerformance) {
        assignPersona(window.browserPerformance, "browserPerformance");
      }
      if (window.features) {
        assignPersona(window.features, "features");
      }
      if (window.i18N) {
        assignPersona(window.i18N, "i18N");
      }
      if (window.qumPerformance) {
        assignPersona(window.qumPerformance, "qumPerformance");
      }
      if (window.designHygiene) {
        assignPersona(window.designHygiene, "designHygiene");
      }

      if (window.vulnerability) {
        assignPersona(window.vulnerability, "vulnerability");
      }

      isLoaded.value = true;
    });

    script.addEventListener("error", () => {
      isLoaded.value = true;
    });

    const latestQUMDataVersion = window.qumReportSummaryPathDetails[0].version;
    script.src = `${process.env.FILE_PATH}${latestQUMDataVersion}/quantitative-user-metrics/execution/${name}.js`;
    document.head.appendChild(script);
  });
};

const assignPersona = (data, category) => {
  data.forEach((item) => {
    //if (window[item.persona]) {
    window[item.persona][category] = item;
    // }
  });
};
</script>

