<script setup>
import { ref, onMounted, watch } from "vue";
import { uuid } from "vue-uuid";
import chartConfig from "../../config/chart";
import useDesignHygieneHelper from "../../use/useDesignHygieneHelper.js";
import useCommonHelper from "../../use/useCommonHelper.js";

const props = defineProps(["tabObject"]);

const designHygieneHelper = useDesignHygieneHelper();
const commonHelper = useCommonHelper();

const selectedExecution = ref("");
const persona = ref("");
const designHygieneData = ref([]);
const scriptItems = ref([]);
const headers = ref([]);
const scripts = ref([]);
const hideOverlay = ref(false);
const data = ref([]);
const summaryDetails = ref([]);
const showDesignHygieneInfo = ref(false);
const showCatDetailsDialog = ref(false);
const designHygieneCategories = ref({});
const actionName = ref("");
const categoryTitle = ref("");
const categoryDetailsData = ref([]);
const showMoreArr = ref([]);
const designHygieneCategoriesPanels = ref([]);
const pageImage = ref("");
const imageDialog = ref(false);
const imageDimensions = ref({});
const pieChartInstance = ref(null);
const chartOptions = ref({});

const categoriesTitles = {
  typographyData: "Typography",
  colorData: "Color",
  cssBoxLayoutData: "Box Layout",
  imageData: "Image",
  miscellaneousData: "Miscellaneous",
};

onMounted(() => {
  designHygieneData.value = props.tabObject.data.qumDataList;
  persona.value = props.tabObject.data.persona;
  selectedExecution.value = window.executionTime;
  initialiseUI();
});

watch(
  () => props.tabObject,
  (newVal) => {
    if (newVal.componentName === "DesignHygieneTab") {
      designHygieneData.value = newVal.data.qumDataList;
      persona.value = newVal.data.persona;
      selectedExecution.value = window.executionTime;
      initialiseUI();
    }
  }
);

watch(
  () => showDesignHygieneInfo.value || showCatDetailsDialog.value,
  (val) => {
    commonHelper.removeBodyScroll(val);
  }
);

const showMore = (index) => {
  showMoreArr.value[index] = !showMoreArr.value[index];

  const copyData = JSON.parse(JSON.stringify(categoryDetailsData.value));
  copyData.forEach((ele, ind) => {
    if (showMoreArr.value[ind]) {
      ele.trimmedSelector = ele.selector;
    } else {
      ele.trimmedSelector = ele.selector.slice(0, 5);
    }
  });

  categoryDetailsData.value = copyData;
};

const initialiseUI = () => {
  if (designHygieneData.value) {
    scriptItems.value = [];
    const scriptsData = designHygieneData.value;
    scripts.value = scriptsData.map((scr) => {
      return {
        id: uuid.v4(),
        name: scr.scriptName,
        scenariosCount: scr.scenarios.length,
        scenarios: scr.scenarios.map((scn) => {
          return {
            id: uuid.v4(),
            name: scn.scenarioName,
            activitiesCount: scn.activities.length,
            activities: scn.activities.map((act) => {
              return {
                id: uuid.v4(),
                name: act.activityName,
                messagesCount: act.actionCount,
                ...act,
                designHygieneList: act.designHygieneList.map((msg) => {
                  return {
                    id: uuid.v4(),
                    ...msg,
                  };
                }),
              };
            }),
          };
        }),
      };
    });
  }

  headers.value = [
    { title: "Tasks", key: "scenario", width: "20%", sortable: false },
    { title: "Scenarios", key: "task", width: "15%", sortable: false },
    { title: "Steps", key: "step", width: "15%", sortable: false },
    { title: "Actions", key: "action", width: "25%", sortable: false },
  ];

  createTableData();
  createSummary();
};

const createSummary = () => {
  let tasks = 0,
    steps = 0,
    actions = 0;
  scripts.value.forEach((script) => {
    tasks += script.scenarios.length;
    script.scenarios.forEach((scenario) => {
      steps += scenario.activities.length;
      scenario.activities.forEach((activity) => {
        actions += activity.designHygieneList.length;
      });
    });
  });
  data.value = [
    {
      name: "Name",
      value: window.info[0].applicationName,
    },
    {
      name: "Persona",
      value: persona.value,
    },
    {
      name: "Tasks",
      value: scripts.value.length,
    },

    {
      name: "Scenarios",
      value: tasks,
    },
    {
      name: "Steps",
      value: steps,
    },
    {
      name: "Actions",
      value: actions,
    },
  ];
  let uniqueFonts = [],
    uniqueColors = [],
    uniqueBgColors = [];

  scripts.value.forEach((scr) => {
    scr.scenarios.forEach((scn) => {
      scn.activities.forEach((act) => {
        act.designHygieneList.forEach((designHygieneItem) => {
          designHygieneItem.data.typographyData.fontFamily.forEach(
            (fontObj) => {
              if (!uniqueFonts.includes(fontObj.value)) {
                uniqueFonts.push(fontObj.value);
              }
            }
          );
          designHygieneItem.data.colorData.color.forEach((colorObj) => {
            if (!uniqueColors.includes(colorObj.value)) {
              uniqueColors.push(colorObj.value);
            }
          });
          designHygieneItem.data.colorData.backGroundColor.forEach(
            (bgColorObj) => {
              if (!uniqueBgColors.includes(bgColorObj.value)) {
                uniqueBgColors.push(bgColorObj.value);
              }
            }
          );
        });
      });
    });
  });

  summaryDetails.value = [
    {
      name: "Unique Fonts",
      y: uniqueFonts.length,
      color: "#ffe188",
    },
    {
      name: "Unique Colors",
      y: uniqueColors.length,
      color: "#88d567",
    },
    {
      name: "Unique Background Colors",
      y: uniqueBgColors.length,
      color: "#b6a3ed",
    },
  ];
  createPieChart();
};

const createPieChart = () => {
  chartOptions.value = {
    ...chartConfig,
    series: [
      {
        name: "Count",
        colorByPoint: true,
        data: summaryDetails.value,
      },
    ],
  };
  // if (pieChartInstance.value instanceof Chart) {
  //   pieChartInstance.value.destroy();
  // }
  // const canvasEle = document.getElementById('design-hyg-pie-chart');
  // const pieChartConfig = JSON.parse(JSON.stringify(chartConfig.pieChart));

  // const pieChartData = {
  //   // labels: summaryDetails.value.map(e => `${e.name}: ${e.value}`),
  //   labels: summaryDetails.value.map(e => e.name),
  //   datasets: [{
  //     label: " ",
  //     data: summaryDetails.value.map(e => e.value),
  //     backgroundColor: summaryDetails.value.map(e => e.color)
  //   }]
  // }
  // pieChartConfig.data = pieChartData;

  // pieChartInstance.value = new Chart(canvasEle, pieChartConfig);
};

const createTableData = () => {
  scriptItems.value = [];
  scripts.value.forEach((scr) => {
    const script = designHygieneHelper.useScriptObj(scr);
    scriptItems.value.push(script);

    scr.scenarios.forEach((scn) => {
      const scenario = designHygieneHelper.useScenarioObj(scn);
      scriptItems.value.push(scenario);

      scn.activities.forEach((act) => {
        const activity = designHygieneHelper.useActivityObj(act);
        scriptItems.value.push(activity);

        act.designHygieneList.forEach((msg) => {
          const item = designHygieneHelper.useMessageObj(msg);
          scriptItems.value.push({
            ...item,
            designHygieneData: msg.data,
            image: msg.screenshot,
          });
        });
      });
    });
  });
};

const showDesignHygineData = (item) => {
  actionName.value = item.action;
  designHygieneCategories.value = item.designHygieneData;
  designHygieneCategoriesPanels.value = Object.keys(item.designHygieneData).map(
    (e, i) => i
  );
  pageImage.value = `../${selectedExecution.value}/quantitative-user-metrics/${item.image}`;
  showDesignHygieneInfo.value = true;
};

const showCategoryDetails = (category, item) => {
  categoryTitle.value = item;
  categoryDetailsData.value = designHygieneCategories.value[category][item];

  showMoreArr.value = Array(
    designHygieneCategories.value[category][item].length
  ).fill(false);

  categoryDetailsData.value.forEach((ele) => {
    if (ele.selector.length > 5) {
      ele.trimmedSelector = ele.selector.slice(0, 5);
    } else {
      ele.trimmedSelector = ele.selector;
    }
  });

  showCatDetailsDialog.value = true;
};

const showImage = async () => {
  imageDimensions.value = await commonHelper.getDimensions(pageImage.value);
  imageDialog.value = true;
};
</script>

