import { ref, nextTick } from 'vue'
import { defineStore } from 'pinia'
import useCommonHelper from '@/use/useCommonHelper';

export const useTabsStore = defineStore('tabs', () => {
  const { useMakeId } = useCommonHelper();
  const currentItemDisplayName = ref("")
  const currentItemType = ref("")
  const currentItemData = ref({})
  const items = ref([])

  const openTab = tabObject => {
    if (Object.keys(tabObject).length === 0) return;

    const isTabOpened = items.value.some(
      (item) => item.displayName === tabObject.displayName
    );

    if (!isTabOpened) {
      items.value.push({
        id: useMakeId(5),
        displayName: tabObject.displayName,
        componentName: tabObject.componentName,
        type: tabObject.type,
        icon: tabObject.icon,
        color: tabObject.color,
        isDirty: false,
        tabData: tabObject,
      });
    } else {
      const selectedItemIndex = items.value.findIndex(
        (item) => item.displayName === tabObject.displayName
      );
      items.value[selectedItemIndex].displayName = tabObject.displayName;
      items.value[selectedItemIndex].componentName = tabObject.componentName;
      if (tabObject.data) {
        items.value[selectedItemIndex].tabData = tabObject;
      }
    }

    nextTick(() => {
      currentItemDisplayName.value = tabObject.displayName;
      currentItemType.value = tabObject.componentName;

      if (tabObject.data) {
        currentItemData.value = tabObject;
      }
    });
  }

  const activateItem = item => {
    nextTick(() => {
      currentItemDisplayName.value = item.displayName;
      currentItemType.value = item.componentName;
    });
  }

  const closeTab = item => {
    const index = items.value.indexOf(item);
    items.value.splice(index, 1);

    if (items.value.length === 1) {
      activateItem(items.value[0]);
    } else if (items.value.length > 1) {
      const activeItemIndex = items.value.findIndex(
        (obj) => obj.displayName == currentItemDisplayName.value
      );
      if (activeItemIndex !== -1) {
        activateItem(items.value[activeItemIndex]);
      } else {
        activateItem(items.value[0]);
      }
    } else {
      currentItemDisplayName.value = "";
      currentItemType.value = "";
    }
  }

  return {
    currentItemDisplayName,
    currentItemType,
    currentItemData,
    items,
    openTab,
    closeTab
  }
})
