import useMetricsHelper from "./useMetricsHelper";

export default function useDesignHygieneHelper() {
  const metricsHelper = useMetricsHelper();

  function useScriptObj(scr) {
    const name = scr.name || scr.scriptName;
    return {
      scenario: name.split(".")[0],
      task: scr.scenarios.length,
      step: metricsHelper.useSumOfTasks(scr),
      action: metricsHelper.useSumOfActions(scr, 'designHygiene'),
    };
  }
  function useScenarioObj(scn) {
    const name = scn.name || scn.scenarioName;
    return {
      scenario: "",
      task: name,
      step: scn.activities.length,
      action: metricsHelper.useSumOfActionsForScenario(scn, 'designHygiene'),
    };
  }
  function useActivityObj(act) {
    return {
      scenario: "",
      task: "",
      step: act.activityName,
      action: act.designHygieneList.length,
    };
  }
  function useMessageObj(msg) {
    return {
      scenario: "",
      task: "",
      step: "",
      action: msg.insightMessage ? msg.insightMessage : "(no message)",
    };
  }

  // function useSumOfTasks(scr) {
  //   let sum = ref(0);
  //   scr.scenarios.forEach((scn) => {
  //     sum.value = sum.value + scn.activities.length;
  //   });
  //   return sum.value;
  // }

  // function useSumOfActions(scr) {
  //   let sum = ref(0);
  //   scr.scenarios.forEach((scn) => {
  //     scn.activities.forEach((act) => {
  //       sum.value = sum.value + act.designHygieneList.length;
  //     });
  //   });
  //   return sum.value;
  // }

  // function useActionsInScenario(scn) {
  //   let sum = ref(0);
  //   scn.activities.forEach((act) => {
  //     sum.value = sum.value + act.designHygieneList.length;
  //   });
  //   return sum.value;
  // }

  return {
    useScriptObj,
    useScenarioObj,
    useActivityObj,
    useMessageObj,
    // useSumOfTasks,
    // useSumOfActions,
    // useActionsInScenario,    
  }
}
