      <v-divider></v-divider>

      <div class="summary-container">
        <v-card class="summary-card" width="50%">
          <v-card-title class="font-weight-bold">Summary</v-card-title>
          <v-card-text>
            <!-- <v-row>
              <v-col cols="5"> -->
            <v-table>
              <template v-slot:default>
                <tbody>
                  <tr v-for="item in summaryDetails" :key="item.key">
