      <v-divider></v-divider>

      <v-data-table-virtual
        :headers="headers"
        :items="scriptItems"
        class="i18NTable"
      >
        <template v-slot:item.scenario="{ item }">
          <div style="word-wrap: break-word">{{ item.scenario }}</div>
        </template>

        <template v-slot:item.task="{ item }">
          <div style="word-wrap: break-word">{{ item.task }}</div>
        </template>

        <template v-slot:item.step="{ item }">
          <span>{{ item.step }}</span>
        </template>

        <template v-slot:item.action="{ item }">
          <span>{{ item.action }}</span>
