            >{{ item.wordCount }}</span
          >
        </template>
        <template v-slot:item.altWordCount="{ item }">
          <span
            :class="
              isScreenshotBtnDisabled(item.alts) ? 'color_red' : 'color_green'
            "
            @click="showElements(item.alts)"
            >{{ item.altWordCount }}</span
          >
        </template>
        <template v-slot:item.ariaLabelWordCount="{ item }">
          <span
            :class="
              isScreenshotBtnDisabled(item.ariaLabels)
                ? 'color_red'
                : 'color_green'
            "
            @click="showElements(item.ariaLabels)"
            >{{ item.ariaLabelWordCount }}</span
          >
        </template>
        <template v-slot:item.tooltipWordCount="{ item }">
          <span
            :class="
              isScreenshotBtnDisabled(item.toolTips)
                ? 'color_red'
                : 'color_green'
            "
            @click="showElements(item.toolTips)"
            >{{ item.tooltipWordCount }}</span
          >
        </template>
        <template v-slot:item.titleWordCount="{ item }">
          <span
            :class="
              isScreenshotBtnDisabled(item.title) ? 'color_red' : 'color_green'
            "
            @click="showElements(item.title)"
            >{{ item.titleWordCount }}</span
          >
        </template>

        <template v-slot:item.totalWordCount="{ item }">
          <span>{{ item.totalWordCount }}</span>
        </template>
      </v-data-table-virtual>
    </div>

    <!-- Element Dialog -->
    <v-dialog
      v-model="elementDialog"
      class="i18n-elements-dailog"
      content-class="no-dialog-overflow"
      :hide-overlay="hideOverlay"
      fullscreen
      persistent
      max-width="75%"
      aria-label="i18n elements"
    >
      <v-card>
        <v-card-title>
          <div class="elements-dailog-title">
            <div>Elements</div>
            <div>
              <div
                @click="elementDialog = false"
                class="elements-dailog-close-icon"
              >
                <v-icon icon="mdi mdi-close"></v-icon>
              </div>
            </div>
          </div>
        </v-card-title>
        <v-card-text class="elements-dailog-text">
          <div v-for="(element, index) in elements" :key="index">
            <v-row>
              <v-col
                cols="3"
                :style="{
                  visibility: element.imagePath ? 'visible' : 'hidden',
                }"
              >
                <div
                  class="element-screenshot"
                  @click="
                    showImage(
                      '../' +
                        selectedExecution +
                        '/quantitative-user-metrics/' +
                        element.imagePath
                    )
                  "
                >
                  <v-card :ripple="false" class="portrait i18NImagesCard"
                    ><img
                      :src="
                        '../' +
                        selectedExecution +
                        '/quantitative-user-metrics/' +
                        element.imagePath
                      "
                      alt="element-image"
                      class="i18NImages"
                      style="
                        width: auto;
                        height: auto;
                        max-width: 200px;
                        max-height: 150px;
                      "
                  /></v-card>
                </div>
              </v-col>
              <v-col
                :cols="element.imagePath ? 8 : 8"
                class="codeSnippetAndWords"
              >
                <v-row>
                  <div class="codeInI18Npopup" :cols="12">
                    <code>
                      {{ element.htmlSnippet }}
                    </code>
                  </div>
                </v-row>
                <v-divider></v-divider>
                <v-row>
                  <div class="wordsInI18Npopup">
                    {{ getWordsSepreatedByComma(element.words) }}
                  </div>
                </v-row>
              </v-col>
            </v-row>
          </div>
        </v-card-text>
      </v-card>
    </v-dialog>

    <!-- Image Dialog -->
    <v-dialog
      class="full-image-dailog"
      v-model="imageDialog"
      content-class="no-dialog-overflow"
      fullscreen
      :hide-overlay="hideOverlay"
      aria-label="i18n elements image"
    >
      <v-card>
        <v-card-text>
          <div @click="imageDialog = false">
            <div class="element-screenshot__content">
              <div
                class="element-screenshot__image"
                :style="{
                  'background-size': '100%',
                  'background-image': `url(${baseImage})`,
                  position: 'relative',
                  width: `${dimension.width}px`,
                  height: `${dimension.height}px`,
                }"
              ></div>
            </div>
          </div>
        </v-card-text>
      </v-card>
    </v-dialog>
  </div>
</template>

<script setup>
import { ref, onMounted, watch } from "vue";
import chartConfig from "../../config/chart";
import { v4 as uuidv4 } from "uuid";
import usei18NHelper from "../../use/usei18NHelper.js";
import useCommonHelper from "../../use/useCommonHelper.js";
import useMetricsHelper from "../../use/useMetricsHelper.js";

const i18NHelper = usei18NHelper();
const metricsHelper = useMetricsHelper();
const commonHelper = useCommonHelper();

const i18NItems = ref([]);
const elementDialog = ref(false);
const scripts = ref([]);
const dimension = ref({});
const baseImage = ref("");
const imageDialog = ref(false);
const hideOverlay = ref(false);
const elements = ref([]);
const totalIssues = ref("");
const totalTasks = ref(0);
const totalScenarios = ref(0);
const totalSteps = ref(0);
const totalActions = ref(0);
const totalAltWordCount = ref(0);
const totalAriaLabelWordCount = ref(0);
const totalToolTipWordCount = ref(0);
const totalTitleWordCount = ref(0);
const totalContentWordCount = ref(0);
const summaryDetails = ref([]);
const metricsDetails = ref([]);
const headers = ref([]);
const scriptItems = ref([]);
const persona = ref("");
const selectedExecution = ref("");
const uuid = ref("");
const pieChartInstance = ref(null);
const props = defineProps(["tabObject"]);
const chartOptions = ref({});
watch(
  () => props.tabObject,
  (newVal) => {
    if (newVal.componentName === "InternationalizationTab") {
      i18NItems.value = newVal.data.qumDataList;
      persona.value = newVal.data.persona;
      selectedExecution.value = window.executionTime;
      initialiseUI();
    }
  }
);

watch(elementDialog, (val) => {
  commonHelper.removeBodyScroll(val);
});

onMounted(() => {
  setUUID();
  i18NItems.value = props.tabObject.data.qumDataList;
  persona.value = props.tabObject.data.persona;
  selectedExecution.value = window.executionTime;
  initialiseUI();
});

const setUUID = () => {
  uuid.value = uuidv4();
};

const initialiseUI = () => {
  if (i18NItems.value) {
    scriptItems.value = [];
    totalContentWordCount.value = 0;
    totalTitleWordCount.value = 0;
    totalAriaLabelWordCount.value = 0;
    totalToolTipWordCount.value = 0;
    totalAltWordCount.value = 0;
    totalIssues.value = "";

    totalTasks.value = 0;
    totalSteps.value = 0;
    totalActions.value = 0;
    const scriptsTemp = i18NItems.value;
    formatSummaryData(scriptsTemp);
    mapScripts(scriptsTemp);
    createTableData();
  } else {
    // $router.push({ name: "upload" });
  }
};

const formatSummaryData = (scriptsTemp) => {
  scripts.value = scriptsTemp.map((scr) => {
    return {
      name: trimScriptName(scr.scriptName),
      language: scr.language,
      scenariosCount: scr.scenarios.length,
      activitiesCount: metricsHelper.useSumOfTasks(scr),
      tasks: metricsHelper.useSumOfTasks(scr),
      actions: metricsHelper.useSumOfActions(scr, "i18N"),
      wordCount: i18NHelper.getScriptWordCount(scr),
      altWordCount: i18NHelper.getAltWordCountForScript(scr),
      ariaLabelWordCount: i18NHelper.getAriaLabelWordCountForScript(scr),
      toolTipWordCount: i18NHelper.getTooltipWordCountForScript(scr),
      titleWordCount: i18NHelper.getTitleWordCountForScript(scr),
      scenarios: mapScenarios(scr),
    };
  });

  totalScenarios.value = scripts.value.length;

  scripts.value.forEach((script) => {
    totalTasks.value += script.tasks;
    totalActions.value += script.actions;
    totalAltWordCount.value += script.altWordCount;
    totalAriaLabelWordCount.value += script.ariaLabelWordCount;
    totalToolTipWordCount.value += script.toolTipWordCount;
    totalTitleWordCount.value += script.titleWordCount;
    totalContentWordCount.value += script.wordCount;
    script.scenarios.forEach((scenario) => {
      totalSteps.value += scenario.activitiesCount;
    });
  });

  totalIssues.value =
    totalAltWordCount.value +
    totalAriaLabelWordCount.value +
    totalToolTipWordCount.value +
    totalTitleWordCount.value +
    totalContentWordCount.value;

  metricsDetails.value = [
    {
      name: "Content",
      y: totalContentWordCount.value,
      color: "#3499ff",
    },
    {
      name: "Alt",
      y: totalAltWordCount.value,
      color: "#ffe188",
    },
    {
      name: "Aria label",
      y: totalAriaLabelWordCount.value,
      color: "#88d567",
    },
    {
      name: "Tool Tip",
      y: totalToolTipWordCount.value,
      color: "#b6a3ed",
    },
    {
      name: "Title",
      y: totalTitleWordCount.value,
      color: "#ffa303",
    },
    // {
    //   key: "Total",
    //   value: totalIssues.value,
    //   color: "#3a86ff"
    // },
  ];

  summaryDetails.value = [
    {
      key: "Name",
      value: window.info[0].applicationName,
    },
    {
      key: "Persona",
      value: persona.value,
    },
    {
      key: "Target language",
      value: [...new Set(scripts.value.map((scr) => scr.language))].join(", "),
    },
    {
      key: "Tasks",
      value: scripts.value.length,
    },
    {
      key: "Scenarios",
      value: totalTasks.value,
    },
    {
      key: "Steps",
      value: totalSteps.value,
    },
    {
      key: "Actions",
      value: totalActions.value,
    },
  ];

  createPieChart();
};

const createPieChart = () => {
  chartOptions.value = {
    ...chartConfig,
    series: [
      {
        name: "Count",
        colorByPoint: true,
        data: metricsDetails.value,
      },
    ],
  };
  // if (pieChartInstance.value instanceof Chart) {
  //   pieChartInstance.value.destroy();
  // }
  // const canvasEle = document.getElementById("i18n-pie-chart");
  // const pieChartConfig = JSON.parse(JSON.stringify(chartConfig.pieChart));

  // const pieChartData = {
  //   // labels: metricsDetails.value.map(e => `${e.key}: ${e.value}`),
  //   labels: metricsDetails.value.map((e) => e.key),
  //   datasets: [
  //     {
  //       label: " ",
  //       data: metricsDetails.value.map((e) => e.value),
  //       backgroundColor: metricsDetails.value.map((e) => e.color),
  //     },
  //   ],
  // };
  // pieChartConfig.data = pieChartData;

  // pieChartInstance.value = new Chart(canvasEle, pieChartConfig);
};

const mapScripts = (scriptsTemp) => {
  headers.value = [
    { title: "Tasks", key: "scenario", width: "20%", sortable: false },
    { title: "Scenarios", key: "task", width: "10%", sortable: false },
    { title: "Steps", key: "step", width: "10%", sortable: false },
    { title: "Actions", key: "action", width: "20%", sortable: false },
    { title: "Content", key: "wordCount", width: "10%", sortable: false },
    { title: "Alt", key: "altWordCount", width: "5%", sortable: false },
    {
      title: "Aria Label",
      key: "ariaLabelWordCount",
      width: "10%",
      sortable: false,
    },
    { title: "Tooltip", key: "tooltipWordCount", width: "5%", sortable: false },
    { title: "Title", key: "titleWordCount", width: "5%", sortable: false },
    { title: "Total", key: "totalWordCount", width: "5%", sortable: false },
  ];

  scripts.value = scriptsTemp.map((scr) => {
    return {
      id: uuid.value,
      scriptName: scr.scriptName,
      onlyName: trimScriptName(scr.scriptName),
      ...scr,
      scenarios: scr.scenarios.map((scn) => {
        return {
          id: uuid.value,
          scenarioName: scn.scenarioName,
          ...scn,
          activities: scn.activities.map((act) => {
            return {
              id: uuid.value,
              ...act,
              i18NDataList: act.i18NDataList.map((step) => {
                return {
                  id: uuid.value,
                  ...step,
                };
              }),
            };
          }),
        };
      }),
    };
  });
};

const mapScenarios = (scr) => {
  return scr.scenarios.map((scn) => {
    return {
      name: scn.scenarioName,
      activitiesCount: scn.activities.length,
      actions: metricsHelper.useSumOfActionsForScenario(scn, "i18N"),
      wordCount: i18NHelper.getScenarioWordCount(scn),
      altWordCount: i18NHelper.getAltWordCountForScenario(scn),
      ariaLabelWordCount: i18NHelper.getAriaLabelWordCountForScenario(scn),
      toolTipWordCount: i18NHelper.getTooltipWordCountForScenario(scn),
      titleWordCount: i18NHelper.getTitleWordCountForScenario(scn),
      activities: mapActivities(scn),
    };
  });
};

const mapActivities = (scn) => {
  return scn.activities.map((act) => {
    return {
      name: act.activityName,
      messagesCount: act.i18NDataList.length,
      wordCount: i18NHelper.getActivityWordCount(act),
      altWordCount: i18NHelper.getAltWordCountForActivity(act),
      ariaLabelWordCount: i18NHelper.getAriaLabelWordCountForActivity(act),
      tooltipWordCount: i18NHelper.getTooltipWordCountForActivity(act),
      titleWordCount: i18NHelper.getTitleWordCountForActivity(act),
      i18NDataList: act.i18NDataList.map((item) => {
        return {
          message: item.insightMessage ? item.insightMessage : "(no message)",
          image: item.screenshot,
          elements: item.data ? i18NHelper.getElements(item.data) : [],
          alts: item.data ? item.data[0].alts : [],
          ariaLabels: item.data ? item.data[0].ariaLabels : [],
          title: item.data ? item.data[0].tittle : [],
          toolTips: item.data ? item.data[0].toolTips : [],
          wordCount: item.data ? i18NHelper.getWordCount(item.data) : 0,
          altWordCount: i18NHelper.getAltWordCount(item.data),
          ariaLabelWordCount: i18NHelper.getAriaLabelWordCount(item.data),
          tooltipWordCount: i18NHelper.getToolTipWordCount(item.data),
          titleWordCount: i18NHelper.getTitleWordCount(item.data),
        };
      }),
    };
  });
};

const createTableData = () => {
  scripts.value.forEach((scr) => {
    const script = {
      id: scr.id,
      scenario: trimScriptName(scr.scriptName),
      task: scr.scenarios.length,
      step: metricsHelper.useSumOfTasks(scr),
      action: metricsHelper.useSumOfActions(scr, "i18N"),
      wordCount: i18NHelper.getScriptWordCount(scr),
      altWordCount: i18NHelper.getAltWordCountForScript(scr),
      ariaLabelWordCount: i18NHelper.getAriaLabelWordCountForScript(scr),
      tooltipWordCount: i18NHelper.getTooltipWordCountForScript(scr),
      titleWordCount: i18NHelper.getTitleWordCountForScript(scr),
      elements: [],
      alts: [],
      ariaLabels: [],
      title: [],
      toolTips: [],
    };
    scriptItems.value.push({
      ...script,
      totalWordCount:
        script.wordCount +
        script.altWordCount +
        script.ariaLabelWordCount +
        script.tooltipWordCount +
        script.titleWordCount,
    });

    scr.scenarios.forEach((scn) => {
      const scenario = {
        id: scn.id,
        scenario: "",
        task: scn.scenarioName,
        step: scn.activities.length,
        action: metricsHelper.useSumOfActionsForScenario(scn, "i18N"),
        wordCount: i18NHelper.getScenarioWordCount(scn),
        altWordCount: i18NHelper.getAltWordCountForScenario(scn),
        ariaLabelWordCount: i18NHelper.getAriaLabelWordCountForScenario(scn),
        tooltipWordCount: i18NHelper.getTooltipWordCountForScenario(scn),
        titleWordCount: i18NHelper.getTitleWordCountForScenario(scn),
        elements: [],
        alts: [],
        ariaLabels: [],
        title: [],
        toolTips: [],
      };

      scriptItems.value.push({
        ...scenario,
        totalWordCount:
          scenario.wordCount +
          scenario.altWordCount +
          scenario.ariaLabelWordCount +
          scenario.tooltipWordCount +
          scenario.titleWordCount,
      });

      scn.activities.forEach((act) => {
        const activity = {
          id: act.id,
          scenario: "",
          task: "",
          step: act.activityName,
          action: act.i18NDataList.length,
          wordCount: i18NHelper.getActivityWordCount(act),
          altWordCount: i18NHelper.getAltWordCountForActivity(act),
          ariaLabelWordCount: i18NHelper.getAriaLabelWordCountForActivity(act),
          tooltipWordCount: i18NHelper.getTooltipWordCountForActivity(act),
          titleWordCount: i18NHelper.getTitleWordCountForActivity(act),
          elements: [],
          alts: [],
          ariaLabels: [],
          title: [],
          toolTips: [],
        };
        scriptItems.value.push({
          ...activity,
          totalWordCount:
            activity.wordCount +
            activity.altWordCount +
            activity.ariaLabelWordCount +
            activity.tooltipWordCount +
            activity.titleWordCount,
        });

        act.i18NDataList.forEach((step) => {
          let item = {
            id: step.id,
            scenario: "",
            task: "",
            step: "",
            action: step.insightMessage ? step.insightMessage : "(no message)",
            wordCount: step.data ? i18NHelper.getWordCount(step.data) : 0,
            altWordCount: step.data ? i18NHelper.getAltWordCount(step.data) : 0,
            ariaLabelWordCount: step.data
              ? i18NHelper.getAriaLabelWordCount(step.data)
              : 0,
            tooltipWordCount: step.data
              ? i18NHelper.getToolTipWordCount(step.data)
              : 0,
            titleWordCount: step.data
              ? i18NHelper.getTitleWordCount(step.data)
              : 0,
            image: step.screenshot,
            elements: step.data ? i18NHelper.getElements(step.data) : [],
            alts: step.data ? step.data[0].alts : [],
            ariaLabels: step.data ? step.data[0].ariaLabels : [],
            title: step.data ? step.data[0].tittle : [],
            toolTips: step.data ? step.data[0].toolTips : [],
          };

          scriptItems.value.push({
            ...item,
            totalWordCount:
              item.wordCount +
              item.altWordCount +
              item.ariaLabelWordCount +
              item.tooltipWordCount +
              item.titleWordCount,
          });
        });
      });
    });
  });
};

const showElements = (data) => {
  elements.value = data;
  elementDialog.value = true;
};

const showImage = async (data) => {
  baseImage.value = "";
  imageDialog.value = true;
  dimension.value = await commonHelper.getDimensions(data);

  baseImage.value = data;
};

const isScreenshotBtnDisabled = (elements) =>
  elements.length === 0 ? false : true;

const getWordsSepreatedByComma = (data) => {
  let words = [];
  if (data.length != 1) {
    data.forEach((item) => {
      words.push(item.word);
    });
    words = words.join(",");
  } else {
    words = data[0].word;
  }
  return decodeHTML(words);
};

const decodeHTML = (data) => {
  try {
    return data ? decodeURI(data) : "";
  } catch (error) {
    // Log error or handle invalid URI data
    console.error("Error decoding URI:", error);
    return data; // Return the original data or an empty string
  }
};

const trimScriptName = (name) => (name ? name.split(".")[0] : "");
</script>

