export default function usei18NHelper() {
  function getWordCount(data) {
    if (data) {
      let sum = 0;

      data.forEach((item) => {
        const { contents } = item;
        contents.forEach((item) => {
          sum = sum + item.words.length;
        });
      });
      return sum;
    } else {
      return 0;
    }
  }

  function getAltWordCount(data) {
    let sum = 0;
    if (data) {
      data.forEach((item) => {
        const { alts } = item;

        alts.forEach((item) => {
          sum = sum + item.words.length;
        });
      });

      return sum;
    } else {
      return 0;
    }
  }

  function getTitleWordCount(data) {
    if (data) {
      let sum = 0;
      data.forEach((item) => {
        const { tittle } = item;
        tittle.forEach((item) => {
          sum = sum + item.words.length;
        });
      });

      return sum;
    } else {
      return 0;
    }
  }

  function getAriaLabelWordCount(data) {
    if (data) {
      let sum = 0;
      data.forEach((item) => {
        const { ariaLabels } = item;

        ariaLabels.forEach((item) => {
          sum = sum + item.words.length;
        });
      });

      return sum;
    } else {
      return 0;
    }
  }

  function getToolTipWordCount(data) {
    if (data) {
      let sum = 0;
      data.forEach((item) => {
        const { toolTips } = item;
        toolTips.forEach((item) => {
          sum = sum + item.words.length;
        });
      });

      return sum;
    } else {
      return 0;
    }
  }

  function getActivityWordCount(act) {
    let sum = 0;
    act.i18NDataList.forEach((item) => {
      sum = sum + getWordCount(item.data);
    });

    return sum;
  }

  function getTooltipWordCountForActivity(act) {
    let sum = 0;
    act.i18NDataList.forEach((item) => {
      sum = sum + getToolTipWordCount(item.data);
    });

    return sum;
  }

  function getAriaLabelWordCountForActivity(act) {
    let sum = 0;
    act.i18NDataList.forEach((item) => {
      sum = sum + getAriaLabelWordCount(item.data);
    });

    return sum;
  }

  function getAltWordCountForActivity(act) {
    let sum = 0;
    act.i18NDataList.forEach((item) => {
      sum = sum + getAltWordCount(item.data);
    });

    return sum;
  }

  function getTitleWordCountForActivity(act) {
    let sum = 0;
    act.i18NDataList.forEach((item) => {
      sum = sum + getTitleWordCount(item.data);
    });

    return sum;
  }

  function getScenarioWordCount(scn) {
    let sum = 0;
    scn.activities.forEach((act) => {
      sum = sum + getActivityWordCount(act);
    });

    return sum;
  }

  function getTooltipWordCountForScenario(scn) {
    let sum = 0;
    scn.activities.forEach((act) => {
      sum = sum + getTooltipWordCountForActivity(act);
    });

    return sum;
  }

  function getAriaLabelWordCountForScenario(scn) {
    let sum = 0;
    scn.activities.forEach((act) => {
      sum = sum + getAriaLabelWordCountForActivity(act);
    });

    return sum;
  }

  function getAltWordCountForScenario(scn) {
    let sum = 0;
    scn.activities.forEach((act) => {
      sum = sum + getAltWordCountForActivity(act);
    });

    return sum;
  }

  function getTitleWordCountForScenario(scn) {
    let sum = 0;
    scn.activities.forEach((act) => {
      sum = sum + getTitleWordCountForActivity(act);
    });

    return sum;
  }

  function getScriptWordCount(scr) {
    let sum = 0;
    scr.scenarios.forEach((scn) => {
      sum = sum + getScenarioWordCount(scn);
    });
    return sum;
  }

  function getAltWordCountForScript(scr) {
    let sum = 0;
    scr.scenarios.forEach((scn) => {
      sum = sum + getAltWordCountForScenario(scn);
    });
    return sum;
  }

  function getAriaLabelWordCountForScript(scr) {
    let sum = 0;
    scr.scenarios.forEach((scn) => {
      sum = sum + getAriaLabelWordCountForScenario(scn);
    });
    return sum;
  }

  function getTooltipWordCountForScript(scr) {
    let sum = 0;
    scr.scenarios.forEach((scn) => {
      sum = sum + getTooltipWordCountForScenario(scn);
    });
    return sum;
  }

  function getTitleWordCountForScript(scr) {
    let sum = 0;
    scr.scenarios.forEach((scn) => {
      sum = sum + getTitleWordCountForScenario(scn);
    });
    return sum;
  }

  function getElements(data) {
    let elements = [];
    data[0].contents.forEach((item) => {
      elements.push(item);
    });
    return elements.flat();
  }

  return {
    getWordCount,
    getAltWordCount,
    getTitleWordCount,
    getAriaLabelWordCount,
    getToolTipWordCount,
    getActivityWordCount,
    getTooltipWordCountForActivity,
    getAriaLabelWordCountForActivity,
    getAltWordCountForActivity,
    getTitleWordCountForActivity,
    getScenarioWordCount,
    getTooltipWordCountForScenario,
    getAriaLabelWordCountForScenario,
    getAltWordCountForScenario,
    getTitleWordCountForScenario,
    getScriptWordCount,
    getAltWordCountForScript,
    getAriaLabelWordCountForScript,
    getTooltipWordCountForScript,
    getTitleWordCountForScript,
    getElements,
  };
}